"use client";

import { useEffect, useMemo, useRef, useState, type ReactNode } from "react";
import PageHero from "@/components/layout/PageHero";
import PageShell from "@/components/layout/PageShell";
import type { Locale } from "@/utils/locale";
import { getUiLabel, warnIfEnglishLabelsInTurkish } from "@/utils/ui-labels";
import {
  REVISION_COPY,
  REVISION_PRIORITY_OPTIONS,
  REVISION_SORT_OPTIONS,
  REVISION_STATUS_OPTIONS,
  type RevisionPriority,
  type RevisionSort,
  type RevisionStatus,
} from "./copy";

type RevisionItem = {
  id: string;
  partCode: string;
  revision: string;
  change: string;
  owner: string;
  dueDate: string;
  priority: RevisionPriority;
  status: RevisionStatus;
  link: string;
  notes: string;
  createdAt: number;
};

const STORAGE_KEY = "project-hub-revisions-v2";

const createId = () =>
  typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(16).slice(2)}`;

const readStorage = () => {
  if (typeof window === "undefined") return [] as RevisionItem[];
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as RevisionItem[];
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

export default function RevisionClient({ locale, heroImage }: { locale: Locale; heroImage: string }) {
  const copy = REVISION_COPY[locale];
  const allLabel = getUiLabel(locale, "all");
  const searchLabel = getUiLabel(locale, "search");
  const sortLabel = getUiLabel(locale, "sort");
  const actionsLabel = getUiLabel(locale, "actions");
  const openLabel = getUiLabel(locale, "open");
  const [items, setItems] = useState<RevisionItem[]>(() => readStorage());
  const hasPersistedRef = useRef(false);
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | RevisionStatus>("all");
  const [priorityFilter, setPriorityFilter] = useState<"all" | RevisionPriority>("all");
  const [sort, setSort] = useState<RevisionSort>("newest");

  const [form, setForm] = useState<Omit<RevisionItem, "id" | "createdAt">>({
    partCode: "",
    revision: "",
    change: "",
    owner: "",
    dueDate: "",
    priority: "medium",
    status: "open",
    link: "",
    notes: "",
  });

  useEffect(() => {
    if (typeof window === "undefined") return;
    if (!hasPersistedRef.current) {
      hasPersistedRef.current = true;
      return;
    }
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    warnIfEnglishLabelsInTurkish("RevisionClient", locale, {
      hero: {
        title: copy.hero.title,
        eyebrow: copy.hero.eyebrow,
      },
      labels: {
        allLabel,
        searchLabel,
        sortLabel,
        actionsLabel,
        openLabel,
      },
    });
  }, [actionsLabel, allLabel, copy.hero.eyebrow, copy.hero.title, locale, openLabel, searchLabel, sortLabel]);

  const statusOrder = useMemo(
    () => new Map(REVISION_STATUS_OPTIONS.map((opt, index) => [opt.value, index])),
    [],
  );
  const priorityOrder = useMemo(
    () => new Map(REVISION_PRIORITY_OPTIONS.map((opt, index) => [opt.value, index])),
    [],
  );

  const handleSubmit = (event: React.FormEvent) => {
    event.preventDefault();
    if (!form.partCode.trim() || !form.revision.trim()) return;
    const nextItem: RevisionItem = {
      id: createId(),
      ...form,
      createdAt: Date.now(),
    };
    setItems((prev) => [nextItem, ...prev]);
    setForm({
      partCode: "",
      revision: "",
      change: "",
      owner: "",
      dueDate: "",
      priority: "medium",
      status: "open",
      link: "",
      notes: "",
    });
  };

  const filteredItems = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    return items.filter((item) => {
      if (statusFilter !== "all" && item.status !== statusFilter) return false;
      if (priorityFilter !== "all" && item.priority !== priorityFilter) return false;
      if (!normalizedQuery) return true;
      const haystack = [
        item.partCode,
        item.revision,
        item.change,
        item.owner,
        item.notes,
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(normalizedQuery);
    });
  }, [items, query, statusFilter, priorityFilter]);

  const sortedItems = useMemo(() => {
    const next = [...filteredItems];
    next.sort((a, b) => {
      if (sort === "due-date") {
        const aTime = a.dueDate ? Date.parse(a.dueDate) : Number.POSITIVE_INFINITY;
        const bTime = b.dueDate ? Date.parse(b.dueDate) : Number.POSITIVE_INFINITY;
        return aTime - bTime;
      }
      if (sort === "priority") {
        return (priorityOrder.get(a.priority) ?? 0) - (priorityOrder.get(b.priority) ?? 0);
      }
      if (sort === "status") {
        return (statusOrder.get(a.status) ?? 0) - (statusOrder.get(b.status) ?? 0);
      }
      return b.createdAt - a.createdAt;
    });
    return next;
  }, [filteredItems, sort, priorityOrder, statusOrder]);

  const updateItem = (id: string, patch: Partial<RevisionItem>) => {
    setItems((prev) => prev.map((item) => (item.id === id ? { ...item, ...patch } : item)));
  };

  const deleteItem = (id: string) => {
    setItems((prev) => prev.filter((item) => item.id !== id));
  };

  return (
    <PageShell>
      <PageHero
        title={copy.hero.title}
        description={copy.hero.description}
        eyebrow={copy.hero.eyebrow}
        imageSrc={heroImage}
        imageAlt={copy.hero.imageAlt}
      />

      <section className="grid gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
        <form onSubmit={handleSubmit} className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h2 className="text-lg font-semibold text-slate-900">{copy.formTitle}</h2>
              <p className="text-xs text-slate-500">{copy.formSubtitle}</p>
            </div>
            <button
              type="submit"
              className="rounded-full bg-slate-900 px-4 py-2 text-[11px] font-semibold text-white hover:bg-slate-800"
            >
              {copy.formCta}
            </button>
          </div>

          <div className="mt-4 grid gap-3 md:grid-cols-2">
            <Field label={copy.fields.partCode}>
              <input
                type="text"
                value={form.partCode}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, partCode: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                required
              />
            </Field>

            <Field label={copy.fields.revision}>
              <input
                type="text"
                value={form.revision}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, revision: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                required
              />
            </Field>

            <Field label={copy.fields.change} className="md:col-span-2">
              <input
                type="text"
                value={form.change}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, change: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.owner}>
              <input
                type="text"
                value={form.owner}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, owner: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.dueDate}>
              <input
                type="date"
                value={form.dueDate}
                onChange={(event) = aria-label="Date input"> setForm((prev) => ({ ...prev, dueDate: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.priority}>
              <select
                value={form.priority}
                onChange={(event) = aria-label="Select field"> setForm((prev) => ({ ...prev, priority: event.target.value as RevisionPriority }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              >
                {REVISION_PRIORITY_OPTIONS.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label[locale]}
                  </option>
                ))}
              </select>
            </Field>

            <Field label={copy.fields.status}>
              <select
                value={form.status}
                onChange={(event) = aria-label="Select field"> setForm((prev) => ({ ...prev, status: event.target.value as RevisionStatus }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              >
                {REVISION_STATUS_OPTIONS.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label[locale]}
                  </option>
                ))}
              </select>
            </Field>

            <Field label={copy.fields.link} className="md:col-span-2">
              <input
                type="url"
                value={form.link}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, link: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="https://"
              />
            </Field>

            <Field label={copy.fields.notes} className="md:col-span-2">
              <textarea
                rows={3}
                value={form.notes}
                onChange={(event) = aria-label="Text area"> setForm((prev) => ({ ...prev, notes: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>
          </div>
        </form>

        <aside className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
          <h2 className="text-lg font-semibold text-slate-900">{copy.filtersTitle}</h2>
          <div className="mt-3 space-y-3">
            <label className="block text-[11px] font-medium text-slate-700">{copy.fields.status}</label>
            <div className="flex flex-wrap gap-2">
              <FilterChip
                active={statusFilter === "all"}
                label={allLabel}
                onClick={() => setStatusFilter("all")}
              />
              {REVISION_STATUS_OPTIONS.map((option) => (
                <FilterChip
                  key={option.value}
                  active={statusFilter === option.value}
                  label={option.label[locale]}
                  onClick={() => setStatusFilter(option.value)}
                />
              ))}
            </div>

            <label className="block text-[11px] font-medium text-slate-700">{copy.fields.priority}</label>
            <div className="flex flex-wrap gap-2">
              <FilterChip
                active={priorityFilter === "all"}
                label={allLabel}
                onClick={() => setPriorityFilter("all")}
              />
              {REVISION_PRIORITY_OPTIONS.map((option) => (
                <FilterChip
                  key={option.value}
                  active={priorityFilter === option.value}
                  label={option.label[locale]}
                  onClick={() => setPriorityFilter(option.value)}
                />
              ))}
            </div>

            <label className="block text-[11px] font-medium text-slate-700">{searchLabel}</label>
            <input
              type="search"
              value={query}
              onChange={(event) = aria-label="Search input"> setQuery(event.target.value)}
              className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              placeholder={copy.searchPlaceholder}
            />

            <label className="block text-[11px] font-medium text-slate-700">{sortLabel}</label>
            <select
              value={sort}
              onChange={(event) = aria-label="Select field"> setSort(event.target.value as RevisionSort)}
              className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
            >
              {REVISION_SORT_OPTIONS.map((option) => (
                <option key={option.value} value={option.value}>
                  {option.label[locale]}
                </option>
              ))}
            </select>

            <div className="rounded-xl border border-amber-200 bg-amber-50 px-3 py-2 text-[11px] text-amber-800">
              <div className="font-semibold">{copy.exportLabel}</div>
              <div>{copy.exportSoon}</div>
            </div>
          </div>
        </aside>
      </section>

      <section className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div>
            <h2 className="text-lg font-semibold text-slate-900">{copy.tableTitle}</h2>
            <span className="text-[11px] text-slate-500">{copy.storageNote}</span>
          </div>
          <button
            type="button"
            disabled
            className="rounded-full border border-amber-300 px-4 py-2 text-[11px] font-semibold text-amber-700 opacity-70"
          >
            {copy.exportLabel} - {copy.exportSoon}
          </button>
        </div>

        {sortedItems.length === 0 ? (
          <p className="mt-4 text-xs text-slate-500">{copy.emptyState}</p>
        ) : (
          <div className="mt-4 overflow-x-auto rounded-2xl border border-slate-200">
            <table className="min-w-full border-collapse text-xs">
              <thead className="bg-slate-50 text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                <tr>
                  <Th>{copy.fields.partCode}</Th>
                  <Th>{copy.fields.revision}</Th>
                  <Th>{copy.fields.change}</Th>
                  <Th>{copy.fields.owner}</Th>
                  <Th>{copy.fields.status}</Th>
                  <Th>{copy.fields.priority}</Th>
                  <Th>{copy.fields.dueDate}</Th>
                  <Th>{copy.fields.link}</Th>
                  <Th>{copy.fields.notes}</Th>
                  <Th>{actionsLabel}</Th>
                </tr>
              </thead>
              <tbody>
                {sortedItems.map((item) => (
                  <tr key={item.id} className="border-t border-slate-100">
                    <Td className="font-semibold text-slate-900">{item.partCode}</Td>
                    <Td>{item.revision}</Td>
                    <Td>{item.change || "-"}</Td>
                    <Td>{item.owner || "-"}</Td>
                    <Td>
                      <select
                        value={item.status}
                        onChange={(event) = aria-label="Select field"> updateItem(item.id, { status: event.target.value as RevisionStatus })}
                        className="rounded-lg border border-slate-300 bg-white px-2 py-1 text-[10px] text-slate-700"
                      >
                        {REVISION_STATUS_OPTIONS.map((option) => (
                          <option key={option.value} value={option.value}>
                            {option.label[locale]}
                          </option>
                        ))}
                      </select>
                    </Td>
                    <Td>
                      <select
                        value={item.priority}
                        onChange={(event) = aria-label="Select field"> updateItem(item.id, { priority: event.target.value as RevisionPriority })}
                        className="rounded-lg border border-slate-300 bg-white px-2 py-1 text-[10px] text-slate-700"
                      >
                        {REVISION_PRIORITY_OPTIONS.map((option) => (
                          <option key={option.value} value={option.value}>
                            {option.label[locale]}
                          </option>
                        ))}
                      </select>
                    </Td>
                    <Td>{item.dueDate || "-"}</Td>
                    <Td>
                      {item.link ? (
                        <a
                          href={item.link}
                          target={item.link.startsWith("http") ? "_blank" : undefined}
                          rel={item.link.startsWith("http") ? "noreferrer" : undefined}
                          className="text-emerald-700 hover:underline"
                        >
                          {openLabel}
                        </a>
                      ) : (
                        "-"
                      )}
                    </Td>
                    <Td className="max-w-[200px] text-[11px] text-slate-600">{item.notes || "-"}</Td>
                    <Td>
                      <button
                        type="button"
                        onClick={() => deleteItem(item.id)}
                        className="rounded-full border border-rose-200 bg-rose-50 px-2 py-1 text-[10px] text-rose-700"
                      >
                        {copy.actions.delete}
                      </button>
                    </Td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </PageShell>
  );
}

function Field({ label, children, className = "" }: { label: string; children: ReactNode; className?: string }) {
  return (
    <label className={`space-y-1 text-[11px] font-medium text-slate-700 ${className}`.trim()}>
      <span>{label}</span>
      {children}
    </label>
  );
}

function Th({ children }: { children: ReactNode }) {
  return <th className="border-b border-slate-200 px-3 py-2 text-left">{children}</th>;
}

function Td({ children, className = "" }: { children: ReactNode; className?: string }) {
  return <td className={`px-3 py-2 align-top text-slate-700 ${className}`}>{children}</td>;
}

function FilterChip({ active, label, onClick }: { active: boolean; label: string; onClick: () => void }) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`rounded-full border px-3 py-1 text-[10px] font-semibold ${
        active ? "border-slate-900 bg-slate-900 text-white" : "border-slate-300 bg-white text-slate-700"
      }`}
    >
      {label}
    </button>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState, type ReactNode } from "react";
import PageHero from "@/components/layout/PageHero";
import PageShell from "@/components/layout/PageShell";
import type { Locale } from "@/utils/locale";
import { getUiLabel, warnIfEnglishLabelsInTurkish } from "@/utils/ui-labels";
import {
  PROJECT_COPY,
  PRIORITY_OPTIONS,
  SORT_OPTIONS,
  STATUS_OPTIONS,
  type ProjectPriority,
  type ProjectStatus,
  type SortOption,
} from "./copy";

type ProjectItem = {
  id: string;
  title: string;
  owner: string;
  area: string;
  status: ProjectStatus;
  priority: ProjectPriority;
  dueDate: string;
  link: string;
  notes: string;
  createdAt: number;
};

const STORAGE_KEY = "project-hub-projects-v2";

const createId = () =>
  typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(16).slice(2)}`;

const readStorage = () => {
  if (typeof window === "undefined") return [] as ProjectItem[];
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as ProjectItem[];
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

export default function ProjectToolsClient({ locale, heroImage }: { locale: Locale; heroImage: string }) {
  const copy = PROJECT_COPY[locale];
  const allLabel = getUiLabel(locale, "all");
  const searchLabel = getUiLabel(locale, "search");
  const sortLabel = getUiLabel(locale, "sort");
  const actionsLabel = getUiLabel(locale, "actions");
  const openLabel = getUiLabel(locale, "open");
  const [items, setItems] = useState<ProjectItem[]>(() => readStorage());
  const hasPersistedRef = useRef(false);
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | ProjectStatus>("all");
  const [priorityFilter, setPriorityFilter] = useState<"all" | ProjectPriority>("all");
  const [sort, setSort] = useState<SortOption>("newest");

  const [form, setForm] = useState<Omit<ProjectItem, "id" | "createdAt">>({
    title: "",
    owner: "",
    area: "",
    status: "open",
    priority: "medium",
    dueDate: "",
    link: "",
    notes: "",
  });

  useEffect(() => {
    if (typeof window === "undefined") return;
    if (!hasPersistedRef.current) {
      hasPersistedRef.current = true;
      return;
    }
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    warnIfEnglishLabelsInTurkish("ProjectToolsClient", locale, {
      hero: {
        title: copy.hero.title,
        eyebrow: copy.hero.eyebrow,
      },
      labels: {
        allLabel,
        searchLabel,
        sortLabel,
        actionsLabel,
        openLabel,
      },
    });
  }, [actionsLabel, allLabel, copy.hero.eyebrow, copy.hero.title, locale, openLabel, searchLabel, sortLabel]);

  const statusOrder = useMemo(
    () => new Map(STATUS_OPTIONS.map((opt, index) => [opt.value, index])),
    [],
  );
  const priorityOrder = useMemo(
    () => new Map(PRIORITY_OPTIONS.map((opt, index) => [opt.value, index])),
    [],
  );

  const handleSubmit = (event: React.FormEvent) => {
    event.preventDefault();
    if (!form.title.trim()) return;

    const nextItem: ProjectItem = {
      id: createId(),
      ...form,
      createdAt: Date.now(),
    };

    setItems((prev) => [nextItem, ...prev]);
    setForm({
      title: "",
      owner: "",
      area: "",
      status: "open",
      priority: "medium",
      dueDate: "",
      link: "",
      notes: "",
    });
  };

  const filteredItems = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    return items.filter((item) => {
      if (statusFilter !== "all" && item.status !== statusFilter) return false;
      if (priorityFilter !== "all" && item.priority !== priorityFilter) return false;
      if (!normalizedQuery) return true;
      const haystack = [
        item.title,
        item.owner,
        item.area,
        item.notes,
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(normalizedQuery);
    });
  }, [items, query, statusFilter, priorityFilter]);

  const sortedItems = useMemo(() => {
    const next = [...filteredItems];
    next.sort((a, b) => {
      if (sort === "due-date") {
        const aTime = a.dueDate ? Date.parse(a.dueDate) : Number.POSITIVE_INFINITY;
        const bTime = b.dueDate ? Date.parse(b.dueDate) : Number.POSITIVE_INFINITY;
        return aTime - bTime;
      }
      if (sort === "priority") {
        return (priorityOrder.get(a.priority) ?? 0) - (priorityOrder.get(b.priority) ?? 0);
      }
      if (sort === "status") {
        return (statusOrder.get(a.status) ?? 0) - (statusOrder.get(b.status) ?? 0);
      }
      return b.createdAt - a.createdAt;
    });
    return next;
  }, [filteredItems, sort, priorityOrder, statusOrder]);

  const updateItem = (id: string, patch: Partial<ProjectItem>) => {
    setItems((prev) => prev.map((item) => (item.id === id ? { ...item, ...patch } : item)));
  };

  const deleteItem = (id: string) => {
    setItems((prev) => prev.filter((item) => item.id !== id));
  };

  return (
    <PageShell>
      <PageHero
        title={copy.hero.title}
        description={copy.hero.description}
        eyebrow={copy.hero.eyebrow}
        imageSrc={heroImage}
        imageAlt={copy.hero.imageAlt}
      />

      <section className="grid gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
        <form onSubmit={handleSubmit} className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h2 className="text-lg font-semibold text-slate-900">{copy.formTitle}</h2>
              <p className="text-xs text-slate-500">{copy.formSubtitle}</p>
            </div>
            <button
              type="submit"
              className="rounded-full bg-slate-900 px-4 py-2 text-[11px] font-semibold text-white hover:bg-slate-800"
            >
              {copy.formCta}
            </button>
          </div>

          <div className="mt-4 grid gap-3 md:grid-cols-2">
            <Field label={copy.fields.title}>
              <input
                type="text"
                value={form.title}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, title: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder={copy.fields.title}
                required
              />
            </Field>

            <Field label={copy.fields.owner}>
              <input
                type="text"
                value={form.owner}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, owner: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.area}>
              <input
                type="text"
                value={form.area}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, area: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.dueDate}>
              <input
                type="date"
                value={form.dueDate}
                onChange={(event) = aria-label="Date input"> setForm((prev) => ({ ...prev, dueDate: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.status}>
              <select
                value={form.status}
                onChange={(event) = aria-label="Select field"> setForm((prev) => ({ ...prev, status: event.target.value as ProjectStatus }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              >
                {STATUS_OPTIONS.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label[locale]}
                  </option>
                ))}
              </select>
            </Field>

            <Field label={copy.fields.priority}>
              <select
                value={form.priority}
                onChange={(event) = aria-label="Select field"> setForm((prev) => ({ ...prev, priority: event.target.value as ProjectPriority }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              >
                {PRIORITY_OPTIONS.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label[locale]}
                  </option>
                ))}
              </select>
            </Field>

            <Field label={copy.fields.link} className="md:col-span-2">
              <input
                type="url"
                value={form.link}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, link: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="https://"
              />
            </Field>

            <Field label={copy.fields.notes} className="md:col-span-2">
              <textarea
                rows={3}
                value={form.notes}
                onChange={(event) = aria-label="Text area"> setForm((prev) => ({ ...prev, notes: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>
          </div>
        </form>

        <aside className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
          <h2 className="text-lg font-semibold text-slate-900">{copy.filtersTitle}</h2>
          <div className="mt-3 space-y-3">
            <label className="block text-[11px] font-medium text-slate-700">{copy.fields.status}</label>
            <div className="flex flex-wrap gap-2">
              <FilterChip
                active={statusFilter === "all"}
                label={allLabel}
                onClick={() => setStatusFilter("all")}
              />
              {STATUS_OPTIONS.map((option) => (
                <FilterChip
                  key={option.value}
                  active={statusFilter === option.value}
                  label={option.label[locale]}
                  onClick={() => setStatusFilter(option.value)}
                />
              ))}
            </div>

            <label className="block text-[11px] font-medium text-slate-700">{copy.fields.priority}</label>
            <div className="flex flex-wrap gap-2">
              <FilterChip
                active={priorityFilter === "all"}
                label={allLabel}
                onClick={() => setPriorityFilter("all")}
              />
              {PRIORITY_OPTIONS.map((option) => (
                <FilterChip
                  key={option.value}
                  active={priorityFilter === option.value}
                  label={option.label[locale]}
                  onClick={() => setPriorityFilter(option.value)}
                />
              ))}
            </div>

            <label className="block text-[11px] font-medium text-slate-700">{searchLabel}</label>
            <input
              type="search"
              value={query}
              onChange={(event) = aria-label="Search input"> setQuery(event.target.value)}
              className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              placeholder={copy.searchPlaceholder}
            />

            <label className="block text-[11px] font-medium text-slate-700">{sortLabel}</label>
            <select
              value={sort}
              onChange={(event) = aria-label="Select field"> setSort(event.target.value as SortOption)}
              className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
            >
              {SORT_OPTIONS.map((option) => (
                <option key={option.value} value={option.value}>
                  {option.label[locale]}
                </option>
              ))}
            </select>

            <div className="rounded-xl border border-amber-200 bg-amber-50 px-3 py-2 text-[11px] text-amber-800">
              <div className="font-semibold">{copy.exportLabel}</div>
              <div>{copy.exportSoon}</div>
            </div>
          </div>
        </aside>
      </section>

      <section className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div>
            <h2 className="text-lg font-semibold text-slate-900">{copy.tableTitle}</h2>
            <span className="text-[11px] text-slate-500">{copy.storageNote}</span>
          </div>
          <button
            type="button"
            disabled
            className="rounded-full border border-amber-300 px-4 py-2 text-[11px] font-semibold text-amber-700 opacity-70"
          >
            {copy.exportLabel} - {copy.exportSoon}
          </button>
        </div>

        {sortedItems.length === 0 ? (
          <p className="mt-4 text-xs text-slate-500">{copy.emptyState}</p>
        ) : (
          <div className="mt-4 overflow-x-auto rounded-2xl border border-slate-200">
            <table className="min-w-full border-collapse text-xs">
              <thead className="bg-slate-50 text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                <tr>
                  <Th>{copy.fields.title}</Th>
                  <Th>{copy.fields.owner}</Th>
                  <Th>{copy.fields.area}</Th>
                  <Th>{copy.fields.status}</Th>
                  <Th>{copy.fields.priority}</Th>
                  <Th>{copy.fields.dueDate}</Th>
                  <Th>{copy.fields.link}</Th>
                  <Th>{copy.fields.notes}</Th>
                  <Th>{actionsLabel}</Th>
                </tr>
              </thead>
              <tbody>
                {sortedItems.map((item) => (
                  <tr key={item.id} className="border-t border-slate-100">
                    <Td className="font-semibold text-slate-900">{item.title}</Td>
                    <Td>{item.owner || "-"}</Td>
                    <Td>{item.area || "-"}</Td>
                    <Td>
                      <select
                        value={item.status}
                        onChange={(event) = aria-label="Select field"> updateItem(item.id, { status: event.target.value as ProjectStatus })}
                        className="rounded-lg border border-slate-300 bg-white px-2 py-1 text-[10px] text-slate-700"
                      >
                        {STATUS_OPTIONS.map((option) => (
                          <option key={option.value} value={option.value}>
                            {option.label[locale]}
                          </option>
                        ))}
                      </select>
                    </Td>
                    <Td>
                      <select
                        value={item.priority}
                        onChange={(event) = aria-label="Select field"> updateItem(item.id, { priority: event.target.value as ProjectPriority })}
                        className="rounded-lg border border-slate-300 bg-white px-2 py-1 text-[10px] text-slate-700"
                      >
                        {PRIORITY_OPTIONS.map((option) => (
                          <option key={option.value} value={option.value}>
                            {option.label[locale]}
                          </option>
                        ))}
                      </select>
                    </Td>
                    <Td>{item.dueDate || "-"}</Td>
                    <Td>
                      {item.link ? (
                        <a
                          href={item.link}
                          target={item.link.startsWith("http") ? "_blank" : undefined}
                          rel={item.link.startsWith("http") ? "noreferrer" : undefined}
                          className="text-emerald-700 hover:underline"
                        >
                          {openLabel}
                        </a>
                      ) : (
                        "-"
                      )}
                    </Td>
                    <Td className="max-w-[220px] text-[11px] text-slate-600">{item.notes || "-"}</Td>
                    <Td>
                      <button
                        type="button"
                        onClick={() => deleteItem(item.id)}
                        className="rounded-full border border-rose-200 bg-rose-50 px-2 py-1 text-[10px] text-rose-700"
                      >
                        {copy.actions.delete}
                      </button>
                    </Td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </PageShell>
  );
}

function Field({ label, children, className = "" }: { label: string; children: ReactNode; className?: string }) {
  return (
    <label className={`space-y-1 text-[11px] font-medium text-slate-700 ${className}`.trim()}>
      <span>{label}</span>
      {children}
    </label>
  );
}

function Th({ children }: { children: ReactNode }) {
  return <th className="border-b border-slate-200 px-3 py-2 text-left">{children}</th>;
}

function Td({ children, className = "" }: { children: ReactNode; className?: string }) {
  return <td className={`px-3 py-2 align-top text-slate-700 ${className}`}>{children}</td>;
}

function FilterChip({ active, label, onClick }: { active: boolean; label: string; onClick: () => void }) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`rounded-full border px-3 py-1 text-[10px] font-semibold ${
        active ? "border-slate-900 bg-slate-900 text-white" : "border-slate-300 bg-white text-slate-700"
      }`}
    >
      {label}
    </button>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState, type ReactNode } from "react";
import PageHero from "@/components/layout/PageHero";
import PageShell from "@/components/layout/PageShell";
import type { Locale } from "@/utils/locale";
import { getUiLabel, warnIfEnglishLabelsInTurkish } from "@/utils/ui-labels";
import {
  RFQ_COPY,
  RFQ_PRIORITY_OPTIONS,
  RFQ_SORT_OPTIONS,
  RFQ_STATUS_OPTIONS,
  type RfqPriority,
  type RfqSort,
  type RfqStatus,
} from "./copy";

type RfqItem = {
  id: string;
  customer: string;
  rfqId: string;
  part: string;
  owner: string;
  dueDate: string;
  priority: RfqPriority;
  status: RfqStatus;
  volume: string;
  sopDate: string;
  link: string;
  notes: string;
  createdAt: number;
};

const STORAGE_KEY = "project-hub-rfq-v2";

const createId = () =>
  typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(16).slice(2)}`;

const readStorage = () => {
  if (typeof window === "undefined") return [] as RfqItem[];
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as RfqItem[];
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

export default function RfqClient({ locale, heroImage }: { locale: Locale; heroImage: string }) {
  const copy = RFQ_COPY[locale];
  const allLabel = getUiLabel(locale, "all");
  const searchLabel = getUiLabel(locale, "search");
  const sortLabel = getUiLabel(locale, "sort");
  const actionsLabel = getUiLabel(locale, "actions");
  const openLabel = getUiLabel(locale, "open");
  const [items, setItems] = useState<RfqItem[]>(() => readStorage());
  const hasPersistedRef = useRef(false);
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | RfqStatus>("all");
  const [priorityFilter, setPriorityFilter] = useState<"all" | RfqPriority>("all");
  const [sort, setSort] = useState<RfqSort>("newest");

  const [form, setForm] = useState<Omit<RfqItem, "id" | "createdAt">>({
    customer: "",
    rfqId: "",
    part: "",
    owner: "",
    dueDate: "",
    priority: "medium",
    status: "new",
    volume: "",
    sopDate: "",
    link: "",
    notes: "",
  });

  useEffect(() => {
    if (typeof window === "undefined") return;
    if (!hasPersistedRef.current) {
      hasPersistedRef.current = true;
      return;
    }
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    warnIfEnglishLabelsInTurkish("RfqClient", locale, {
      hero: {
        title: copy.hero.title,
        eyebrow: copy.hero.eyebrow,
      },
      labels: {
        allLabel,
        searchLabel,
        sortLabel,
        actionsLabel,
        openLabel,
      },
    });
  }, [actionsLabel, allLabel, copy.hero.eyebrow, copy.hero.title, locale, openLabel, searchLabel, sortLabel]);

  const statusOrder = useMemo(
    () => new Map(RFQ_STATUS_OPTIONS.map((opt, index) => [opt.value, index])),
    [],
  );
  const priorityOrder = useMemo(
    () => new Map(RFQ_PRIORITY_OPTIONS.map((opt, index) => [opt.value, index])),
    [],
  );

  const handleSubmit = (event: React.FormEvent) => {
    event.preventDefault();
    if (!form.customer.trim() || !form.rfqId.trim() || !form.part.trim()) return;
    const nextItem: RfqItem = {
      id: createId(),
      ...form,
      createdAt: Date.now(),
    };
    setItems((prev) => [nextItem, ...prev]);
    setForm({
      customer: "",
      rfqId: "",
      part: "",
      owner: "",
      dueDate: "",
      priority: "medium",
      status: "new",
      volume: "",
      sopDate: "",
      link: "",
      notes: "",
    });
  };

  const filteredItems = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    return items.filter((item) => {
      if (statusFilter !== "all" && item.status !== statusFilter) return false;
      if (priorityFilter !== "all" && item.priority !== priorityFilter) return false;
      if (!normalizedQuery) return true;
      const haystack = [
        item.customer,
        item.rfqId,
        item.part,
        item.owner,
        item.notes,
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(normalizedQuery);
    });
  }, [items, query, statusFilter, priorityFilter]);

  const sortedItems = useMemo(() => {
    const next = [...filteredItems];
    next.sort((a, b) => {
      if (sort === "due-date") {
        const aTime = a.dueDate ? Date.parse(a.dueDate) : Number.POSITIVE_INFINITY;
        const bTime = b.dueDate ? Date.parse(b.dueDate) : Number.POSITIVE_INFINITY;
        return aTime - bTime;
      }
      if (sort === "priority") {
        return (priorityOrder.get(a.priority) ?? 0) - (priorityOrder.get(b.priority) ?? 0);
      }
      if (sort === "status") {
        return (statusOrder.get(a.status) ?? 0) - (statusOrder.get(b.status) ?? 0);
      }
      return b.createdAt - a.createdAt;
    });
    return next;
  }, [filteredItems, sort, priorityOrder, statusOrder]);

  const updateItem = (id: string, patch: Partial<RfqItem>) => {
    setItems((prev) => prev.map((item) => (item.id === id ? { ...item, ...patch } : item)));
  };

  const deleteItem = (id: string) => {
    setItems((prev) => prev.filter((item) => item.id !== id));
  };

  return (
    <PageShell>
      <PageHero
        title={copy.hero.title}
        description={copy.hero.description}
        eyebrow={copy.hero.eyebrow}
        imageSrc={heroImage}
        imageAlt={copy.hero.imageAlt}
      />

      <section className="grid gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
        <form onSubmit={handleSubmit} className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h2 className="text-lg font-semibold text-slate-900">{copy.formTitle}</h2>
              <p className="text-xs text-slate-500">{copy.formSubtitle}</p>
            </div>
            <button
              type="submit"
              className="rounded-full bg-slate-900 px-4 py-2 text-[11px] font-semibold text-white hover:bg-slate-800"
            >
              {copy.formCta}
            </button>
          </div>

          <div className="mt-4 grid gap-3 md:grid-cols-2">
            <Field label={copy.fields.customer}>
              <input
                type="text"
                value={form.customer}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, customer: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                required
              />
            </Field>

            <Field label={copy.fields.rfqId}>
              <input
                type="text"
                value={form.rfqId}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, rfqId: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                required
              />
            </Field>

            <Field label={copy.fields.part} className="md:col-span-2">
              <input
                type="text"
                value={form.part}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, part: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                required
              />
            </Field>

            <Field label={copy.fields.owner}>
              <input
                type="text"
                value={form.owner}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, owner: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.dueDate}>
              <input
                type="date"
                value={form.dueDate}
                onChange={(event) = aria-label="Date input"> setForm((prev) => ({ ...prev, dueDate: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.priority}>
              <select
                value={form.priority}
                onChange={(event) = aria-label="Select field"> setForm((prev) => ({ ...prev, priority: event.target.value as RfqPriority }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              >
                {RFQ_PRIORITY_OPTIONS.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label[locale]}
                  </option>
                ))}
              </select>
            </Field>

            <Field label={copy.fields.status}>
              <select
                value={form.status}
                onChange={(event) = aria-label="Select field"> setForm((prev) => ({ ...prev, status: event.target.value as RfqStatus }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              >
                {RFQ_STATUS_OPTIONS.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label[locale]}
                  </option>
                ))}
              </select>
            </Field>

            <Field label={copy.fields.volume}>
              <input
                type="text"
                value={form.volume}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, volume: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.sopDate}>
              <input
                type="date"
                value={form.sopDate}
                onChange={(event) = aria-label="Date input"> setForm((prev) => ({ ...prev, sopDate: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>

            <Field label={copy.fields.link} className="md:col-span-2">
              <input
                type="url"
                value={form.link}
                onChange={(event) = aria-label="Input field"> setForm((prev) => ({ ...prev, link: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="https://"
              />
            </Field>

            <Field label={copy.fields.notes} className="md:col-span-2">
              <textarea
                rows={3}
                value={form.notes}
                onChange={(event) = aria-label="Text area"> setForm((prev) => ({ ...prev, notes: event.target.value }))}
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </Field>
          </div>
        </form>

        <aside className="rounded-3xl border border-slate-200 bg-white p-6 text-sm shadow-sm">
          <h2 className="text-lg font-semibold text-slate-900">{copy.filtersTitle}</h2>
          <div className="mt-3 space-y-3">
            <label className="block text-[11px] font-medium text-slate-700">{copy.fields.status}</label>
            <div className="flex flex-wrap gap-2">
              <FilterChip
                active={statusFilter === "all"}
                label={allLabel}
                onClick={() => setStatusFilter("all")}
              />
              {RFQ_STATUS_OPTIONS.map((option) => (
                <FilterChip
                  key={option.value}
                  active={statusFilter === option.value}
                  label={option.label[locale]}
                  onClick={() => setStatusFilter(option.value)}
                />
              ))}
            </div>

