        location: locale === "tr" ? "Arka sol flanş" : "Rear-left flange",
        contactArea: locale === "tr" ? "Yaylı baskı pabuç" : "Spring contact pad",
        reactionPoint: locale === "tr" ? "Yan dayama B" : "Side stop B",
