              options={DATUM_IDS.map((id) => ({ value: id, label: copy.datumOptions[id] }))}
            />
            <SelectField
              label={copy.fields.secondaryDatum}
              value={form.secondaryDatum}
              onChange={(value) => handleFormChange("secondaryDatum", value as DatumId)}
              options={DATUM_IDS.map((id) => ({ value: id, label: copy.datumOptions[id] }))}
            />
            <SelectField
