                    <p>
                      {locale === "tr" ? "Parça-fikstür diferansiyel genleşme" : "Part-fixture differential growth"}: {" "}
                      {computed.differentialGrowth !== null ? `${computed.differentialGrowth.toFixed(3)} mm` : "-"}
                    </p>
                    <p>
