// app/tools/machine-elements/page.tsx
import { useMemo, useState } from "react";
import PageShell from "@/components/layout/PageShell";
import ToolDocTabs from "@/components/tools/ToolDocTabs";
import type { ToolDocsResponse } from "@/lib/toolDocs/types";

type BearingInputs = {
  C: string; // dinamik yük kapasitesi (kN)
  P: string; // eşdeğer yük (kN)
  n: string; // rpm
};

type KeyInputs = {
  torque: string; // Nm
  shaftDia: string; // mm
  keyWidth: string; // mm
  keyHeight: string; // mm
  keyLength: string; // mm
  shearAllow: string; // MPa
  bearingAllow: string; // MPa
};

type GearInputs = {
  power: string; // kW
  rpm: string; // rpm
  pinionDia: string; // mm
  face: string; // mm
  pressureAngle: string; // deg
  gearRatio: string; // i = z2/z1
};

const BEARING_INIT: BearingInputs = {
  C: "25",
  P: "5",
  n: "1500",
};

const KEY_INIT: KeyInputs = {
  torque: "180",
  shaftDia: "40",
  keyWidth: "12",
  keyHeight: "8",
  keyLength: "50",
  shearAllow: "100",
  bearingAllow: "200",
};

const GEAR_INIT: GearInputs = {
  power: "5.5",
  rpm: "1450",
  pinionDia: "120",
  face: "40",
  pressureAngle: "20",
  gearRatio: "3",
};

type MachineElementsClientProps = {
  initialDocs?: ToolDocsResponse | null;
};

export default function MachineElementsPage({ initialDocs }: MachineElementsClientProps) {
  return (
    <PageShell>
      <ToolDocTabs slug="machine-elements" initialDocs={initialDocs}>
      <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
        <div className="mb-3 flex items-center gap-2">
          <span className="rounded-full bg-slate-900 px-3 py-1 text-[10px] font-semibold uppercase tracking-wide text-white">
            Makine Elemanları
          </span>
          <span className="rounded-full bg-indigo-50 px-3 py-1 text-[10px] font-medium text-indigo-700">
            Çoklu Hesap
          </span>
        </div>
        <h1 className="text-lg font-semibold text-slate-900">
          Makine Elemanları Hızlı Paket
        </h1>
        <p className="mt-2 text-xs text-slate-600">
          Öğrenciler ve mezunların sık aradığı üç temel kontrol: (1) rulman L10 ömrü, (2)
          kamalı milde kesme/ezilme, (3) basit düz dişli yükleri (Ft, Fr) ve tork. Hızlı
          kontrol amaçlıdır; katalog/standart değerleri mutlaka doğrulayın.
        </p>
      </section>

      <BearingBlock />
      <KeyBlock />
      <GearBlock />
          </ToolDocTabs>
    </PageShell>
