import { useLocale } from "@/components/i18n/LocaleProvider";

type MaterialInfo = {
  name: string;
  yieldStrength: number; // akma dayanımı (MPa)
};

const MATERIALS: MaterialInfo[] = [
  { name: "S235", yieldStrength: 235 },
  { name: "S355", yieldStrength: 355 },
  { name: "C45 (Islahlı ~ 600 MPa)", yieldStrength: 600 },
  { name: "50CrV4 (Islahlı ~ 1100 MPa)", yieldStrength: 1100 },
  { name: "Alüminyum 6013 (T6 ~ 300 MPa)", yieldStrength: 300 },
];

type SimpleStressClientProps = {
  initialDocs?: ToolDocsResponse | null;
};

export default function SimpleStressPage({ initialDocs }: SimpleStressClientProps) {
  const { locale } = useLocale();
  const methodNotes = getToolMethodNotes("simple-stress", locale);
  const [force, setForce] = useState<number>(0);
  const [area, setArea] = useState<number>(0);
  const [material, setMaterial] = useState<string>(MATERIALS[0].name);

  const selectedMaterial = MATERIALS.find((m) => m.name === material)!;

  const stress = area > 0 ? force / area : 0; // MPa
  const safetyFactor = stress > 0 ? selectedMaterial.yieldStrength / stress : 0;

  let statusMessage = "";
  if (stress === 0) {
    statusMessage = "Hesaplama için değer giriniz.";
  } else if (safetyFactor >= 2) {
    statusMessage = "Durum: Emniyette (n ≥ 2).";
  } else if (safetyFactor >= 1.2) {
    statusMessage = "Durum: Sınırda (1.2 ≤ n < 2).";
  } else {
    statusMessage = "Durum: Riskli (n < 1.2).";
  }

  return (
    <PageShell>
      <ToolDocTabs slug="simple-stress" initialDocs={initialDocs}>
        <main className="min-h-screen bg-[#E5E5E7] flex items-center justify-center px-4 py-10">
          <div className="max-w-xl w-full bg-white shadow-lg rounded-xl p-6 border border-gray-200">
        <h1 className="text-2xl font-bold text-[#2A2A2E] mb-3">
          Basit Çekme Gerilmesi Hesaplayıcı
        </h1>

        <p className="text-sm text-gray-700 mb-4">
          Kuvvet ve kesit alanıyla gerilmeyi hesapla, malzeme dayanımı ile karşılaştır.
        </p>

        {/* INPUT ALANI */}
        <div className="space-y-4">
          {/* Kuvvet */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Kuvvet (N)
            </label>
            <input
              type="number"
              className="w-full border p-2 rounded"
              value={force}
              onChange={(e) = aria-label="Number input"> setForce(Number(e.target.value))}
              placeholder="ör. 5000"
            />
          </div>

          {/* Alan */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Kesit Alanı (mm²)
            </label>
            <input
              type="number"
              className="w-full border p-2 rounded"
              value={area}
              onChange={(e) = aria-label="Number input"> setArea(Number(e.target.value))}
              placeholder="ör. 100"
            />
          </div>

          {/* Malzeme */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Malzeme
            </label>
            <select
              className="w-full border p-2 rounded"
              value={material}
              onChange={(e) = aria-label="Select field"> setMaterial(e.target.value)}
            >
              {MATERIALS.map((m) => (
                <option key={m.name} value={m.name}>
                  {m.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* SONUÇLAR */}
        <div className="mt-6 border-t pt-4">
          <h2 className="text-lg font-semibold mb-2">Sonuçlar</h2>

          <p className="text-sm mb-1">
            <strong>Gerilme (σ): </strong>
            {stress.toFixed(2)} MPa
          </p>

          <p className="text-sm mb-1">
            <strong>Akma Dayanımı (Re): </strong>
            {selectedMaterial.yieldStrength} MPa
          </p>

          <p className="text-sm mb-3">
            <strong>Emniyet Katsayısı (n): </strong>
            {safetyFactor > 0 ? safetyFactor.toFixed(2) : "-"}
          </p>

          <p
            className={`text-sm font-semibold ${
              safetyFactor >= 2
                ? "text-green-600"
                : safetyFactor >= 1.2
                ? "text-orange-500"
                : "text-red-600"
            }`}
          >
            {statusMessage}
          </p>
        </div>

        <p className="text-xs text-gray-500 mt-4">
          Not: Hesaplamalar teoriktir. Kritik tasarımlarda ilgili standartlara
          başvurulmalıdır.
        </p>
          </div>
        </main>
        {methodNotes ? <ToolMethodNotes notes={methodNotes} /> : null}
      </ToolDocTabs>
    </PageShell>
  );
}

"use client";

// app/tools/strength-statics/page.tsx
import { useMemo, useState } from "react";
import PageShell from "@/components/layout/PageShell";
import ToolDocTabs from "@/components/tools/ToolDocTabs";
import type { ToolDocsResponse } from "@/lib/toolDocs/types";

type CombinedInputs = {
  axial: string; // N
  shear: string; // N
  area: string; // mm2
  yield: string; // MPa
};

type BucklingInputs = {
  length: string; // mm
  k: string; // boyutsuz
  E: string; // GPa
  I: string; // mm4
  area: string; // mm2 (opsiyonel r için)
};

type ShaftInputs = {
  moment: string; // Nm
  torque: string; // Nm
  diameter: string; // mm
  yield: string; // MPa
};

const COMBINED_INIT: CombinedInputs = {
  axial: "12000",
  shear: "6000",
  area: "450",
  yield: "250",
};

const BUCKLING_INIT: BucklingInputs = {
  length: "1200",
  k: "1.0",
  E: "210",
  I: "32000",
  area: "900",
};

const SHAFT_INIT: ShaftInputs = {
  moment: "250", // Nm
  torque: "180", // Nm
  diameter: "40",
  yield: "350",
};

type StrengthStaticsClientProps = {
  initialDocs?: ToolDocsResponse | null;
};

export default function StrengthStaticsPage({ initialDocs }: StrengthStaticsClientProps) {
  return (
    <PageShell>
      <ToolDocTabs slug="strength-statics" initialDocs={initialDocs}>
      <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
        <div className="mb-3 flex items-center gap-2">
          <span className="rounded-full bg-slate-900 px-3 py-1 text-[10px] font-semibold uppercase tracking-wide text-white">
            Mukavemet
          </span>
          <span className="rounded-full bg-indigo-50 px-3 py-1 text-[10px] font-medium text-indigo-700">
            Çoklu Hesap
          </span>
        </div>
        <h1 className="text-lg font-semibold text-slate-900">
          Mukavemet & Statik Hızlı Paket
        </h1>
        <p className="mt-2 text-xs text-slate-600">
          Öğrenciler ve mezunların sık baktığı üç hesap: (1) eksenel+kesme birleşik gerilme
          ve emniyet, (2) Euler burkulma ve narinlik, (3) dairesel milde eğilme+tork
          birleşik gerilme. Hızlı kontrol amaçlıdır; detaylı tasarımda ilgili standartları
          ve güvenlik katsayılarını kontrol edin.
        </p>
      </section>

      <CombinedBlock />
      <BucklingBlock />
      <ShaftBlock />
          </ToolDocTabs>
    </PageShell>
  );
}

function CombinedBlock() {
  const [inp, setInp] = useState<CombinedInputs>(COMBINED_INIT);

  const res = useMemo(() => {
    const axial = Number(inp.axial);
    const shear = Number(inp.shear);
    const A = Number(inp.area);
    const sy = Number(inp.yield);
    const ok = axial > 0 && A > 0 && sy > 0 && shear >= 0;
    if (!ok) return null;
    const sigma = axial / A; // MPa (N/mm2)
    const tau = shear / A;
    const mises = Math.sqrt(sigma * sigma + 3 * tau * tau);
    const n = sy / mises;
    return { sigma, tau, mises, n };
  }, [inp]);

  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
      <h2 className="mb-3 text-sm font-semibold text-slate-900">
        1) Eksenel + Kesme Birleşik Gerilme (von Mises)
      </h2>
      <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
        <Field label="Eksenel yük N" value={inp.axial} onChange={(v) => setInp({ ...inp, axial: v })} />
        <Field label="Kesme yükü N" value={inp.shear} onChange={(v) => setInp({ ...inp, shear: v })} />
        <Field label="Kesit alanı A [mm²]" value={inp.area} onChange={(v) => setInp({ ...inp, area: v })} />
        <Field label="Akma dayanımı Sy [MPa]" value={inp.yield} onChange={(v) => setInp({ ...inp, yield: v })} />
      </div>
      {res ? (
        <div className="mt-3 grid gap-2 sm:grid-cols-2 lg:grid-cols-4">
          <ResultRow label="σ = N/A" value={`${res.sigma.toFixed(2)} MPa`} />
          <ResultRow label="τ = V/A" value={`${res.tau.toFixed(2)} MPa`} />
          <ResultRow label="σvm" value={`${res.mises.toFixed(2)} MPa`} />
          <ResultRow label="Emniyet n = Sy/σvm" value={`${res.n.toFixed(2)}`} />
        </div>
      ) : (
        <p className="mt-2 text-[11px] text-red-600">Pozitif ve mantıklı değerler gir.</p>
      )}
    </section>
  );
}

function BucklingBlock() {
  const [inp, setInp] = useState<BucklingInputs>(BUCKLING_INIT);

  const res = useMemo(() => {
    const L = Number(inp.length);
    const k = Number(inp.k);
    const E = Number(inp.E); // GPa
    const I = Number(inp.I); // mm4
    const A = Number(inp.area);
    const ok = L > 0 && k > 0 && E > 0 && I > 0;
    if (!ok) return null;
    const L_eff = k * L;
    const E_mpa = E * 1000; // GPa -> MPa (N/mm2)
    const Pcr = (Math.PI * Math.PI * E_mpa * I) / (L_eff * L_eff); // N
    let slender: number | null = null;
    if (A > 0) {
      const r = Math.sqrt(I / A);
      slender = L_eff / r;
    }
    return { Pcr, L_eff, slender };
  }, [inp]);

  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
      <h2 className="mb-3 text-sm font-semibold text-slate-900">
        2) Euler Burkulma & Narinlik
      </h2>
      <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-5">
        <Field label="Serbest boy L [mm]" value={inp.length} onChange={(v) => setInp({ ...inp, length: v })} />
        <Field
          label="K (uç koşulu)"
          value={inp.k}
          onChange={(v) => setInp({ ...inp, k: v })}
          helper="Sabit-sabit ~0.7, sabit-serbest 2.0, mafsal-mafsal 1.0"
        />
        <Field label="E [GPa]" value={inp.E} onChange={(v) => setInp({ ...inp, E: v })} />
        <Field label="Atalet I [mm⁴]" value={inp.I} onChange={(v) => setInp({ ...inp, I: v })} />
        <Field
          label="Alan A [mm²] (opsiyonel)"
          value={inp.area}
          onChange={(v) => setInp({ ...inp, area: v })}
          helper="Narinlik için"
        />
      </div>
      {res ? (
        <div className="mt-3 grid gap-2 sm:grid-cols-2 lg:grid-cols-4">
          <ResultRow label="Leff = K·L" value={`${res.L_eff.toFixed(0)} mm`} />
          <ResultRow label="Pcr (Euler)" value={`${res.Pcr.toFixed(0)} N`} />
          {res.slender !== null && (
            <ResultRow label="Narinlik λ = Leff/r" value={`${res.slender.toFixed(0)}`} />
          )}
          <div className="rounded-lg bg-slate-50 px-3 py-2 text-[11px] text-slate-700 sm:col-span-2 lg:col-span-2">
            İnce çubuk varsayımı: elastik burkulma, malzeme doğrusal. Plastik sınır, yerel
            burkulma ve başlangıç kusurları için ilgili standardı kontrol edin.
          </div>
        </div>
      ) : (
        <p className="mt-2 text-[11px] text-red-600">Pozitif ve mantıklı değerler gir.</p>
      )}
    </section>
  );
}

function ShaftBlock() {
  const [inp, setInp] = useState<ShaftInputs>(SHAFT_INIT);

  const res = useMemo(() => {
    const M_Nm = Number(inp.moment);
    const T_Nm = Number(inp.torque);
    const d = Number(inp.diameter);
    const sy = Number(inp.yield);
    const ok = M_Nm >= 0 && T_Nm >= 0 && d > 0 && sy > 0;
    if (!ok) return null;
    const M = M_Nm * 1000; // Nmm
    const T = T_Nm * 1000; // Nmm
    const denom = Math.PI * Math.pow(d, 3);
    const sigma_b = (32 * M) / denom;
    const tau_t = (16 * T) / denom;
    const mises = Math.sqrt(sigma_b * sigma_b + 3 * tau_t * tau_t);
    const n = sy / mises;
    return { sigma_b, tau_t, mises, n };
  }, [inp]);

  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
      <h2 className="mb-3 text-sm font-semibold text-slate-900">
        3) Mil Eğilme + Tork (Dairesel, tam kesit)
      </h2>
      <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
        <Field label="Eğilme momenti M [Nm]" value={inp.moment} onChange={(v) => setInp({ ...inp, moment: v })} />
        <Field label="Tork T [Nm]" value={inp.torque} onChange={(v) => setInp({ ...inp, torque: v })} />
        <Field label="Çap d [mm]" value={inp.diameter} onChange={(v) => setInp({ ...inp, diameter: v })} />
        <Field label="Akma dayanımı Sy [MPa]" value={inp.yield} onChange={(v) => setInp({ ...inp, yield: v })} />
      </div>
      {res ? (
        <div className="mt-3 grid gap-2 sm:grid-cols-2 lg:grid-cols-4">
          <ResultRow label="σb" value={`${res.sigma_b.toFixed(1)} MPa`} />
          <ResultRow label="τt" value={`${res.tau_t.toFixed(1)} MPa`} />
          <ResultRow label="σvm" value={`${res.mises.toFixed(1)} MPa`} />
          <ResultRow label="Emniyet n = Sy/σvm" value={`${res.n.toFixed(2)}`} />
        </div>
      ) : (
        <p className="mt-2 text-[11px] text-red-600">Pozitif değerler gir.</p>
      )}
      <p className="mt-2 text-[11px] text-slate-600">
        Not: Dolu dairesel kesit için J = πd⁴/32, Wb = πd³/32. Yivli/kanallı miller için
        zayıflama katsayısı ve gerilme yoğunlaşması dikkate alınmalıdır.
      </p>
    </section>
  );
}

function Field({
  label,
  value,
  onChange,
  helper,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  helper?: string;
}) {
  return (
    <label className="space-y-1">
      <span className="block text-[11px] font-medium text-slate-700">{label}</span>
      <input
        type="number"
        value={value}
        onChange={(e) = aria-label="Number input"> onChange(e.target.value)}
        className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
      />
      {helper && <span className="text-[10px] text-slate-500">{helper}</span>}
    </label>
  );
}

function ResultRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between rounded-lg bg-slate-50 px-3 py-1.5">
      <span className="text-[11px] text-slate-600">{label}</span>
      <span className="font-mono text-[11px] font-semibold text-slate-900">{value}</span>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { addDoc, collection, limit, onSnapshot, orderBy, query, serverTimestamp } from "firebase/firestore";
import { useOptionalAuth } from "@/components/auth/AuthProvider";
import useFirebaseServices from "@/components/firebase/useFirebaseServices";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { getMessages } from "@/utils/messages";

type Comment = {
  id: string;
  content: string;
  displayName?: string;
  createdAt?: { seconds?: number };
};

export default function CommentStream() {
  const { locale } = useLocale();
  const copy = getMessages(locale).components.commentStream;
  const auth = useOptionalAuth();
  const { services, ready: servicesReady } = useFirebaseServices();
  const authUnavailable = Boolean(auth && !auth.available);
  const isDemoMode = servicesReady && !services && !authUnavailable;
  const user = auth?.user ?? null;
  const authLoading = auth?.loading ?? false;

  const [content, setContent] = useState("");
  const [comments, setComments] = useState<Comment[]>([]);
  const [saving, setSaving] = useState(false);
  const [commentsLoading, setCommentsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [authError, setAuthError] = useState<string | null>(null);
  const [authPending, setAuthPending] = useState(false);

  const userLabel = useMemo(
    () => user?.displayName ?? user?.email ?? copy.userFallback,
    [user, copy.userFallback],
  );
  const loadFailedMessage = copy.errors.loadFailed;

  useEffect(() => {
    if (!servicesReady) return;

    if (isDemoMode) {
      setCommentsLoading(false);
      return;
    }

    const firestore = services?.firestore;
    if (!firestore) {
      setCommentsLoading(false);
      return;
    }

    const q = query(collection(firestore, "comments"), orderBy("createdAt", "desc"), limit(6));
    const unsub = onSnapshot(
      q,
      (snapshot) => {
        const next = snapshot.docs.map((doc) => ({ id: doc.id, ...(doc.data() as Omit<Comment, "id">) }));
        setComments(next);
        setCommentsLoading(false);
      },
      (err) => {
        console.error("[comments] Firestore listen failed:", err);
        setError(loadFailedMessage);
        setCommentsLoading(false);
      },
    );
    return () => unsub();
  }, [isDemoMode, services, servicesReady, loadFailedMessage]);

  const handleLogin = async () => {
    if (!auth?.loginWithGoogle || !services || authUnavailable) return;
    setAuthPending(true);
    setAuthError(null);

    try {
      await auth.loginWithGoogle();
    } catch (err) {
      console.error("[comments] Login failed:", err);
      setAuthError(copy.errors.loginFailed);
    } finally {
      setAuthPending(false);
    }
  };

  const handleLogout = async () => {
    if (!auth?.logout) return;
    setAuthPending(true);
    setAuthError(null);
    try {
      await auth.logout();
    } catch (err) {
      console.error("[comments] Logout failed:", err);
      setAuthError(copy.errors.logoutFailed);
    } finally {
      setAuthPending(false);
    }
  };

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const trimmed = content.trim();
    if (!trimmed) return;
    if (!user && !isDemoMode) return;

    setSaving(true);
    setError(null);

    if (isDemoMode) {
      const now = Math.floor(Date.now() / 1000);
      const nextComment: Comment = {
        id: `demo-${Date.now()}`,
        content: trimmed,
        displayName: copy.demoUser,
        createdAt: { seconds: now },
      };
      setComments((prev) => [nextComment, ...prev].slice(0, 6));
      setContent("");
      setSaving(false);
      return;
    }

    try {
      const firestore = services?.firestore;
      if (!firestore) return;

      await addDoc(collection(firestore, "comments"), {
        content: trimmed,
        displayName: user?.displayName ?? user?.email ?? copy.userFallback,
        uid: user?.uid,
        createdAt: serverTimestamp(),
      });
      setContent("");
    } catch (err) {
      console.error("[comments] Comment save failed:", err);
      setError(copy.errors.saveFailed);
    } finally {
      setSaving(false);
    }
  };

  const placeholder = !servicesReady
    ? copy.placeholders.loading
    : isDemoMode
    ? copy.placeholders.demo
    : authUnavailable
      ? copy.placeholders.authUnavailable
    : user
      ? copy.placeholders.signedIn
      : copy.placeholders.signedOut;

  const helperText = !servicesReady
    ? copy.helpers.loading
    : isDemoMode
    ? copy.helpers.demo
    : authUnavailable
      ? copy.helpers.authUnavailable
    : user
      ? copy.helpers.signedIn
      : copy.helpers.signedOut;

  const submitDisabled = saving || !content.trim() || (!isDemoMode && !user) || !servicesReady || authUnavailable;

  return (
    <div className="relative overflow-hidden rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
      <div className="absolute inset-0 bg-gradient-to-br from-emerald-50/70 via-transparent to-sky-50/60" aria-hidden />
      <div className="relative space-y-4">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.18em] text-emerald-600">{copy.kicker}</p>
            <h3 className="text-xl font-semibold text-slate-900">{copy.title}</h3>
          </div>
          <div className="flex flex-wrap items-center gap-2">
