"use client";

import { useEffect, useRef, useState, type MouseEvent } from "react";
import {
  CONSENT_COOKIE,
  CONSENT_PREFS_KEY,
  CONSENT_STORAGE_KEY,
  readConsentPrefs,
  readConsentStatus,
  resolveConsentPrefs,
  type ConsentPrefs,
  type ConsentStatus,
} from "@/utils/consent";
import type { Messages } from "@/utils/messages";

const CONSENT_MAX_AGE = 60 * 60 * 24 * 365;

const DEFAULT_PREFS: ConsentPrefs = {
  analytics: false,
  advertising: false,
};

type ConsentBannerProps = {
  copy: Messages["components"]["consent"];
};

export default function ConsentBanner({ copy }: ConsentBannerProps) {
  const [mounted, setMounted] = useState(false);
  const [bannerVisible, setBannerVisible] = useState(false);
  const [prefsOpen, setPrefsOpen] = useState(false);
  const [prefs, setPrefs] = useState<ConsentPrefs>(DEFAULT_PREFS);

  const modalRef = useRef<HTMLDivElement | null>(null);
  const lastFocusedRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    const frameId = window.requestAnimationFrame(() => {
      setMounted(true);
      const status = readConsentStatus();
      const storedPrefs = readConsentPrefs();
      if (!status) {
        setBannerVisible(true);
        setPrefs(storedPrefs ?? DEFAULT_PREFS);
        return;
      }
      setBannerVisible(false);
      setPrefs(resolveConsentPrefs(status, storedPrefs));
    });

    return () => {
      window.cancelAnimationFrame(frameId);
    };
  }, []);

  useEffect(() => {
    if (!prefsOpen) return;
    const modal = modalRef.current;
    if (!modal) return;

    lastFocusedRef.current = document.activeElement as HTMLElement | null;

    const focusableSelector =
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])';

    const getFocusable = () =>
      Array.from(modal.querySelectorAll<HTMLElement>(focusableSelector)).filter(
        (node) => !node.hasAttribute("disabled"),
      );

    const focusables = getFocusable();
    (focusables[0] ?? modal).focus();

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        setPrefsOpen(false);
        return;
      }
      if (event.key !== "Tab") return;
      const items = getFocusable();
      if (items.length === 0) {
        event.preventDefault();
        return;
      }
      const first = items[0];
      const last = items[items.length - 1];
      if (event.shiftKey && document.activeElement === first) {
        event.preventDefault();
        last.focus();
      } else if (!event.shiftKey && document.activeElement === last) {
        event.preventDefault();
        first.focus();
      }
    };

    document.addEventListener("keydown", handleKeyDown);
    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      lastFocusedRef.current?.focus();
    };
  }, [prefsOpen]);

  const persistConsent = (status: ConsentStatus, nextPrefs: ConsentPrefs) => {
    try {
      window.localStorage.setItem(CONSENT_STORAGE_KEY, status);
      window.localStorage.setItem(CONSENT_PREFS_KEY, JSON.stringify(nextPrefs));
    } catch {
      // ignore storage errors
    }

    document.cookie = `${CONSENT_COOKIE}=${encodeURIComponent(status)}; Path=/; Max-Age=${CONSENT_MAX_AGE}; SameSite=Lax`;
    document.documentElement.dataset.consent = status;
  };

  const handleAccept = () => {
    const nextPrefs = { analytics: true, advertising: true };
    setPrefs(nextPrefs);
    persistConsent("accept", nextPrefs);
    setBannerVisible(false);
    setPrefsOpen(false);
  };

  const handleReject = () => {
    setPrefs(DEFAULT_PREFS);
    persistConsent("reject", DEFAULT_PREFS);
    setBannerVisible(false);
    setPrefsOpen(false);
  };

  const handleSavePrefs = () => {
    persistConsent("custom", prefs);
    setBannerVisible(false);
    setPrefsOpen(false);
  };

  const handleOverlayClick = (event: MouseEvent<HTMLDivElement>) => {
    if (event.target !== event.currentTarget) return;
    setPrefsOpen(false);
  };

  if (!mounted) return null;

  return (
    <>
      {prefsOpen ? (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 px-4 py-6"
          role="dialog"
          aria-modal="true"
          aria-labelledby="consent-title"
          aria-describedby="consent-description"
          onClick={handleOverlayClick}
        >
          <div
            ref={modalRef}
            tabIndex={-1}
            className="w-full max-w-lg rounded-3xl border border-slate-200 bg-white p-6 shadow-xl outline-none"
          >
            <div className="flex items-start justify-between gap-4">
              <div>
                <h2 id="consent-title" className="text-lg font-semibold text-slate-900">
                  {copy.preferencesTitle}
                </h2>
                <p id="consent-description" className="mt-2 text-sm text-slate-600">
                  {copy.preferencesDescription}
                </p>
              </div>
              <button
                type="button"
                className="rounded-full border border-slate-200 bg-white px-3 py-1 text-xs font-semibold text-slate-600 hover:text-slate-900"
                onClick={() => setPrefsOpen(false)}
                aria-label={copy.close}
              >
                {copy.close}
              </button>
            </div>

            <div className="mt-5 space-y-3">
              <ConsentToggle
                label={copy.necessaryLabel}
                description={copy.necessaryDescription}
                checked
                locked
                helper={copy.alwaysOn}
              />
              <ConsentToggle
                label={copy.analyticsLabel}
                description={copy.analyticsDescription}
                checked={prefs.analytics}
                onChange={(value) => setPrefs((prev) => ({ ...prev, analytics: value }))}
              />
              <ConsentToggle
                label={copy.advertisingLabel}
                description={copy.advertisingDescription}
                checked={prefs.advertising}
                onChange={(value) => setPrefs((prev) => ({ ...prev, advertising: value }))}
              />
            </div>

            <div className="mt-6 flex flex-wrap items-center justify-end gap-2">
              <button
                type="button"
                className="rounded-full border border-slate-200 bg-white px-4 py-2 text-xs font-semibold text-slate-600 hover:text-slate-900"
                onClick={handleReject}
              >
                {copy.reject}
              </button>
              <button
                type="button"
                className="rounded-full bg-emerald-600 px-4 py-2 text-xs font-semibold text-white shadow-sm transition hover:bg-emerald-500"
                onClick={handleSavePrefs}
              >
                {copy.save}
              </button>
            </div>
          </div>
        </div>
      ) : null}

      {bannerVisible ? (
        <div className="fixed inset-x-0 bottom-4 z-40 px-4">
          <div className="mx-auto flex max-w-4xl flex-col gap-4 rounded-3xl border border-slate-200 bg-white/95 p-5 shadow-lg backdrop-blur sm:flex-row sm:items-center sm:justify-between">
            <div className="space-y-2">
              <h2 className="text-sm font-semibold text-slate-900">{copy.title}</h2>
              <p className="text-xs text-slate-600 sm:text-sm">{copy.description}</p>
            </div>
            <div className="flex flex-wrap items-center gap-2">
              <button
                type="button"
                className="rounded-full border border-slate-200 bg-white px-4 py-2 text-xs font-semibold text-slate-700 hover:text-slate-900"
                onClick={handleReject}
              >
                {copy.reject}
              </button>
              <button
                type="button"
                className="rounded-full border border-emerald-200 bg-emerald-50 px-4 py-2 text-xs font-semibold text-emerald-700 hover:bg-emerald-100"
                onClick={() => setPrefsOpen(true)}
              >
                {copy.preferences}
              </button>
              <button
                type="button"
                className="rounded-full bg-emerald-600 px-4 py-2 text-xs font-semibold text-white shadow-sm transition hover:bg-emerald-500"
                onClick={handleAccept}
              >
                {copy.accept}
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </>
  );
}

type ConsentToggleProps = {
  label: string;
  description: string;
  checked: boolean;
  onChange?: (value: boolean) => void;
  locked?: boolean;
  helper?: string;
};

function ConsentToggle({ label, description, checked, onChange, locked = false, helper }: ConsentToggleProps) {
  const id = `consent-${label.replace(/\s+/g, "-").toLowerCase()}`;
  return (
    <label
      htmlFor={id}
      className={`flex items-center justify-between gap-4 rounded-2xl border border-slate-200 bg-slate-50 p-4 ${
        locked ? "opacity-80" : ""
      }`}
    >
      <div className="space-y-1">
        <div className="flex items-center gap-2">
          <span className="text-sm font-semibold text-slate-900">{label}</span>
          {locked && helper ? (
            <span className="rounded-full bg-emerald-100 px-2 py-0.5 text-[10px] font-semibold text-emerald-700">
              {helper}
            </span>
          ) : null}
        </div>
        <p className="text-xs text-slate-600">{description}</p>
      </div>
      <span className="relative inline-flex h-6 w-11 items-center">
        <input
          id={id}
          type="checkbox"
          className="peer sr-only"
          checked={checked}
          disabled={locked}
          onChange={(event) = aria-label={id}> onChange?.(event.target.checked)}
          aria-checked={checked}
        />
        <span className="absolute h-6 w-11 rounded-full bg-slate-200 transition peer-checked:bg-emerald-500 peer-disabled:bg-slate-300" />
        <span className="absolute left-0.5 top-0.5 h-5 w-5 rounded-full bg-white shadow-sm transition peer-checked:translate-x-5 peer-disabled:bg-slate-100" />
      </span>
    </label>
  );
}

"use client";

import { useEffect, useRef } from "react";

type Particle = {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
};

const createParticle = (width: number, height: number): Particle => ({
  x: Math.random() * width,
  y: Math.random() * height,
  vx: (Math.random() - 0.5) * 0.3,
  vy: (Math.random() - 0.5) * 0.3,
  size: Math.random() * 2 + 1,
});

const updateParticle = (particle: Particle, width: number, height: number) => {
  particle.x += particle.vx;
  particle.y += particle.vy;

  if (particle.x < 0 || particle.x > width) particle.vx *= -1;
  if (particle.y < 0 || particle.y > height) particle.vy *= -1;
};

const drawParticle = (ctx: CanvasRenderingContext2D, particle: Particle) => {
  ctx.fillStyle = "rgba(34, 211, 238, 0.5)";
  ctx.beginPath();
  ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
  ctx.fill();
};

const getSettings = (width: number) => {
  const isMobile = width < 640;
  return {
    particleCount: isMobile ? 24 : 42,
    connectionDistance: isMobile ? 100 : 135,
  };
};

export default function ParticleBackground() {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;

    let frameId = 0;
    let width = window.innerWidth;
    let height = window.innerHeight;
    let particles: Particle[] = [];
    let settings = getSettings(width);

    const init = () => {
      canvas.width = width;
      canvas.height = height;
      particles = Array.from({ length: settings.particleCount }, () => createParticle(width, height));
    };

    const animate = () => {
      if (document.visibilityState === "hidden") {
        frameId = window.requestAnimationFrame(animate);
        return;
      }

      ctx.clearRect(0, 0, width, height);

      for (let i = 0; i < particles.length; i += 1) {
        const particle = particles[i];
        updateParticle(particle, width, height);
        drawParticle(ctx, particle);

        for (let j = i + 1; j < particles.length; j += 1) {
          const next = particles[j];
          const dx = particle.x - next.x;
          const dy = particle.y - next.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist >= settings.connectionDistance) continue;

          ctx.beginPath();
          ctx.strokeStyle = `rgba(34, 211, 238, ${1 - dist / settings.connectionDistance})`;
          ctx.lineWidth = 0.5;
          ctx.moveTo(particle.x, particle.y);
          ctx.lineTo(next.x, next.y);
          ctx.stroke();
        }
      }

      frameId = window.requestAnimationFrame(animate);
    };

    const handleResize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      settings = getSettings(width);
      init();
    };

    window.addEventListener("resize", handleResize);
    init();
    animate();

    return () => {
      window.removeEventListener("resize", handleResize);
      window.cancelAnimationFrame(frameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed left-0 top-0 -z-10 h-full w-full bg-neutral-950 pointer-events-none" />;
}

"use client";

import { useMemo, useState } from "react";
import Link from "next/link";
import type { Locale } from "@/utils/locale";
import { formatMessage, getMessages } from "@/utils/messages";
import { withLocalePrefix } from "@/utils/locale-path";
import type { MaterialCategory, MaterialEntry } from "@/src/data/materials/types";

const CATEGORY_ALL = "all" as const;

const CATEGORY_ORDER: MaterialCategory[] = [
  "steel",
  "stainless",
  "tool",
  "cast-iron",
  "aluminum",
  "copper",
  "nickel",
  "titanium",
  "magnesium",
  "plastics",
  "elastomer",
  "composites",
];

type MaterialsLibraryClientProps = {
  materials: MaterialEntry[];
  locale: Locale;
};

type IndexedMaterial = MaterialEntry & {
  categoryLabel: string;
  searchText: string;
};

const parseNumber = (value: string) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const formatNumber = (value: number | null, locale: Locale, options?: Intl.NumberFormatOptions) => {
  if (value === null || !Number.isFinite(value)) return "—";
  return value.toLocaleString(locale === "tr" ? "tr-TR" : "en-US", options);
};

export default function MaterialsLibraryClient({ materials, locale }: MaterialsLibraryClientProps) {
  const copy = getMessages(locale).pages.materials;
  const localeLower = locale === "tr" ? "tr-TR" : "en-US";

  const [query, setQuery] = useState("");
  const [category, setCategory] = useState<typeof CATEGORY_ALL | MaterialCategory>(CATEGORY_ALL);
  const [yieldMin, setYieldMin] = useState("");
  const [yieldMax, setYieldMax] = useState("");
  const [modulusMin, setModulusMin] = useState("");
  const [modulusMax, setModulusMax] = useState("");

  const normalizedQuery = query.trim().toLocaleLowerCase(localeLower);
  const yieldMinValue = parseNumber(yieldMin);
  const yieldMaxValue = parseNumber(yieldMax);
  const modulusMinValue = parseNumber(modulusMin);
  const modulusMaxValue = parseNumber(modulusMax);

  const indexedMaterials = useMemo<IndexedMaterial[]>(() => {
    return materials.map((material) => {
      const categoryLabel = copy.categories[material.category] ?? material.category;
      const searchText = [
        material.name,
        material.standard,
        material.category,
        categoryLabel,
        material.notes ?? "",
      ]
        .join(" ")
        .toLocaleLowerCase(localeLower);
      return { ...material, categoryLabel, searchText };
    });
  }, [materials, copy.categories, localeLower]);

  const filtered = useMemo(() => {
    const matches = indexedMaterials.filter((material) => {
      if (category !== CATEGORY_ALL && material.category !== category) return false;
      if (normalizedQuery && !material.searchText.includes(normalizedQuery)) return false;

      if (yieldMinValue !== null) {
        if (material.yield === null || material.yield < yieldMinValue) return false;
      }
      if (yieldMaxValue !== null) {
        if (material.yield === null || material.yield > yieldMaxValue) return false;
      }
      if (modulusMinValue !== null && material.E < modulusMinValue) return false;
      if (modulusMaxValue !== null && material.E > modulusMaxValue) return false;

      return true;
    });

    return matches.sort((a, b) => a.name.localeCompare(b.name, localeLower));
  }, [indexedMaterials, category, normalizedQuery, yieldMinValue, yieldMaxValue, modulusMinValue, modulusMaxValue, localeLower]);

  const handleClear = () => {
    setQuery("");
    setCategory(CATEGORY_ALL);
    setYieldMin("");
    setYieldMax("");
    setModulusMin("");
    setModulusMax("");
  };

  return (
    <div className="space-y-6">
      <section className="rounded-3xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="space-y-4">
          <div className="space-y-2">
            <h2 className="text-lg font-semibold text-slate-900">{copy.search.title}</h2>
            <p className="text-sm text-slate-600">{copy.search.description}</p>
          </div>

          <div className="grid gap-4 lg:grid-cols-[minmax(0,1.1fr)_minmax(0,1fr)]">
            <div className="space-y-1">
              <label className="text-[11px] font-medium text-slate-700">{copy.search.label}</label>
              <input
                type="search"
                inputMode="search"
                value={query}
                onChange={(event) = aria-label="Search input"> setQuery(event.target.value)}
                placeholder={copy.search.placeholder}
                className="w-full rounded-xl border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/30"
              />
            </div>

            <div className="space-y-1">
              <label className="text-[11px] font-medium text-slate-700">{copy.filters.categoryLabel}</label>
              <select
                value={category}
                onChange={(event) = aria-label="Select field"> setCategory(event.target.value as typeof CATEGORY_ALL | MaterialCategory)}
                className="w-full rounded-xl border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/30"
              >
                <option value={CATEGORY_ALL}>{copy.filters.allCategories}</option>
                {CATEGORY_ORDER.map((value) => (
                  <option key={value} value={value}>
                    {copy.categories[value] ?? value}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid gap-4 lg:grid-cols-2">
            <div className="space-y-2">
              <label className="text-[11px] font-medium text-slate-700">{copy.filters.yieldLabel}</label>
              <div className="grid gap-2 sm:grid-cols-2">
                <input
                  type="number"
                  value={yieldMin}
                  onChange={(event) = aria-label="Number input"> setYieldMin(event.target.value)}
                  placeholder={copy.filters.yieldMin}
                  className="w-full rounded-xl border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/30"
                  min={0}
                />
                <input
                  type="number"
                  value={yieldMax}
                  onChange={(event) = aria-label="Number input"> setYieldMax(event.target.value)}
                  placeholder={copy.filters.yieldMax}
                  className="w-full rounded-xl border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/30"
                  min={0}
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[11px] font-medium text-slate-700">{copy.filters.modulusLabel}</label>
              <div className="grid gap-2 sm:grid-cols-2">
                <input
                  type="number"
                  value={modulusMin}
                  onChange={(event) = aria-label="Number input"> setModulusMin(event.target.value)}
                  placeholder={copy.filters.modulusMin}
                  className="w-full rounded-xl border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/30"
                  min={0}
                  step="any"
                />
                <input
                  type="number"
                  value={modulusMax}
                  onChange={(event) = aria-label="Number input"> setModulusMax(event.target.value)}
                  placeholder={copy.filters.modulusMax}
                  className="w-full rounded-xl border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/30"
                  min={0}
                  step="any"
                />
              </div>
            </div>
          </div>

          <div className="flex flex-wrap items-center justify-between gap-3 text-xs text-slate-500">
            <span>{formatMessage(copy.results.countLabel, { count: filtered.length })}</span>
            <button
              type="button"
              onClick={handleClear}
              className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-600 transition hover:border-slate-300 hover:text-slate-800"
            >
              {copy.filters.clear}
            </button>
          </div>
        </div>
      </section>

      {filtered.length === 0 ? (
        <section className="rounded-2xl border border-dashed border-slate-200 bg-white p-6 text-center">
          <p className="text-sm font-semibold text-slate-700">{copy.results.emptyTitle}</p>
          <p className="mt-1 text-xs text-slate-500">{copy.results.emptyDescription}</p>
        </section>
      ) : (
        <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-3">
          {filtered.map((material) => (
            <article
              key={material.id}
              className="flex h-full flex-col justify-between rounded-2xl border border-slate-200 bg-white p-4 shadow-sm"
            >
              <div className="space-y-2">
                <div className="flex items-start justify-between gap-2">
                  <div>
                    <h3 className="text-base font-semibold text-slate-900">{material.name}</h3>
                    <p className="text-xs text-slate-500">
                      {copy.card.standard}: {material.standard}
                    </p>
                  </div>
                  <span className="rounded-full bg-slate-100 px-2 py-0.5 text-[10px] font-semibold text-slate-600">
                    {material.categoryLabel}
                  </span>
                </div>
                <dl className="space-y-1 text-[11px] text-slate-600">
                  <div className="flex items-center justify-between">
                    <dt>{copy.card.density}</dt>
                    <dd className="font-mono text-slate-900">
                      {formatNumber(material.density, locale, { maximumFractionDigits: 0 })} kg/m3
                    </dd>
                  </div>
                  <div className="flex items-center justify-between">
                    <dt>{copy.card.modulus}</dt>
                    <dd className="font-mono text-slate-900">
                      {formatNumber(material.E, locale, { maximumFractionDigits: 1 })}
                    </dd>
                  </div>
                  <div className="flex items-center justify-between">
                    <dt>{copy.card.yield}</dt>
                    <dd className="font-mono text-slate-900">
                      {formatNumber(material.yield, locale, { maximumFractionDigits: 0 })}
                    </dd>
                  </div>
                </dl>
              </div>
              <Link
                href={withLocalePrefix(`/materials/${material.id}`, locale)}
                className="mt-4 inline-flex items-center justify-center rounded-full border border-slate-200 px-3 py-1.5 text-[11px] font-semibold text-slate-700 transition hover:border-slate-300 hover:text-slate-900"
              >
                {copy.card.cta}
              </Link>
            </article>
          ))}
        </section>
      )}

      <section className="rounded-2xl border border-amber-200 bg-amber-50 px-5 py-4 text-xs text-amber-700">
        {copy.disclaimer}
      </section>
    </div>
  );
}

"use client";

import { useEffect, useState, type ReactNode } from "react";
import Link from "next/link";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { getMessages } from "@/utils/messages";
import { withLocalePrefix } from "@/utils/locale-path";
import materialsData from "@/data/reference/materials.json";
import threadsData from "@/data/reference/threads.json";
import fitsData from "@/data/reference/fits.json";
import hardnessData from "@/data/reference/hardness.json";
import surfaceFinishData from "@/data/reference/surface-finish.json";
import frictionQuickData from "@/data/reference/friction-quick.json";
import siPrefixesData from "@/data/reference/si-prefixes.json";

type LocalizedText = { tr: string; en: string };

type ReferenceColumn = {
  key: string;
  label: LocalizedText;
};

type ReferenceSection = {
  id: string;
  title: LocalizedText;
  description?: LocalizedText;
  columns: ReferenceColumn[];
  rows: Array<Record<string, unknown>>;
  note?: LocalizedText;
  layout?: "table" | "cards";
};

type ReferenceLink = {
  href: string;
  label: LocalizedText;
};

type SectionWithRows = ReferenceSection & { filteredRows: Array<Record<string, unknown>> };

const SECTIONS: ReferenceSection[] = [
  threadsData,
  fitsData,
  hardnessData,
  surfaceFinishData,
  frictionQuickData,
  siPrefixesData,
  materialsData,
];

const SECTION_LINKS: Record<string, ReferenceLink[]> = {
  materials: [
    {
      href: "/tools/material-cards",
      label: { tr: "Malzeme Kartlarına git", en: "Go to Material Cards" },
    },
  ],
  threads: [
    {
      href: "/tools/bolt-calculator",
      label: { tr: "Cıvata Boyut & Tork", en: "Bolt Size & Torque" },
    },
    {
      href: "/tools/bolt-database",
      label: { tr: "Cıvata Veri Merkezi", en: "Bolt Data Center" },
    },
  ],
  "friction-quick": [
    {
      href: "/tools/bolt-calculator",
      label: { tr: "Cıvata Boyut & Tork", en: "Bolt Size & Torque" },
    },
  ],
  fits: [
    {
      href: "/tools/materials-manufacturing",
