"use client";

import { useEffect, useMemo, useState, type RefObject } from "react";
import { buildQualityPdfFilename, exportElementToPdf } from "@/lib/pdf/exportElementToPdf";
import { getJSON, setJSON } from "@/lib/storage";
import type { QualityReportActionsCopy } from "@/data/quality-tools/report-actions";

type SavedReport<T> = {
  id: string;
  title: string;
  createdAt: string;
  updatedAt: string;
  data: T;
};

type ReportActionsProps<T> = {
  toolKey: string;
  currentData: T;
  onLoadData: (data: T) => void;
  onDemoFill: () => void;
  onReset: () => void;
  reportRootRef: RefObject<HTMLElement | null>;
  copy: QualityReportActionsCopy;
};

const wait = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

const safePart = (value: string) =>
  value
    .trim()
    .replace(/[^\w\s-]+/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "")
    .toLowerCase();

function formatDateLabel(value: string) {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleString();
}

function downloadJsonFile(filename: string, payload: unknown) {
  const blob = new Blob([JSON.stringify(payload, null, 2)], {
    type: "application/json;charset=utf-8",
  });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
}

function readSavedReports<T>(storageKey: string): SavedReport<T>[] {
  const loaded = getJSON<SavedReport<T>[]>(storageKey, []);
  return Array.isArray(loaded) ? loaded : [];
}

export default function ReportActions<T>({
  toolKey,
  currentData,
  onLoadData,
  onDemoFill,
  onReset,
  reportRootRef,
  copy,
}: ReportActionsProps<T>) {
  const storageKey = useMemo(() => `aielab:quality:${toolKey}:saved`, [toolKey]);
  const [savedReports, setSavedReports] = useState<SavedReport<T>[]>([]);
  const [isSaveModalOpen, setIsSaveModalOpen] = useState(false);
  const [isManageModalOpen, setIsManageModalOpen] = useState(false);
  const [titleInput, setTitleInput] = useState("");
  const [statusText, setStatusText] = useState<string | null>(null);

  useEffect(() => {
    const timeoutId = window.setTimeout(() => {
      setSavedReports(readSavedReports<T>(storageKey));
    }, 0);

    return () => window.clearTimeout(timeoutId);
  }, [storageKey]);

  useEffect(() => {
    if (!statusText) return;
    const timeoutId = window.setTimeout(() => setStatusText(null), 2000);
    return () => window.clearTimeout(timeoutId);
  }, [statusText]);

  function persist(next: SavedReport<T>[]) {
    setSavedReports(next);
    setJSON(storageKey, next);
  }

  function openSaveModal() {
    setTitleInput("");
    setIsSaveModalOpen(true);
  }

  function createSavedReport() {
    const now = new Date().toISOString();
    const normalizedTitle = titleInput.trim() || `${toolKey.toUpperCase()} ${now.slice(0, 10)}`;
    const nextEntry: SavedReport<T> = {
      id: `rep_${Date.now().toString(36)}`,
      title: normalizedTitle,
      createdAt: now,
      updatedAt: now,
      data: currentData,
    };
    persist([nextEntry, ...savedReports]);
    setIsSaveModalOpen(false);
    setStatusText(copy.saveSuccess);
  }

  async function exportCurrentPdf() {
    const element = reportRootRef.current;
    if (!element) return;
    try {
      const filename = buildQualityPdfFilename(toolKey);
      await exportElementToPdf(element, filename);
    } catch {
      setStatusText(copy.exportPdfError);
    }
  }

  function exportSavedJson(entry: SavedReport<T>) {
    const titlePart = safePart(entry.title) || "report";
    const filename = `AI-Engineers-Lab_${safePart(toolKey) || "quality"}_${titlePart}.json`;
    downloadJsonFile(filename, entry);
  }

  async function exportSavedPdf(entry: SavedReport<T>) {
    const element = reportRootRef.current;
    if (!element) return;

    try {
      onLoadData(entry.data);
      await wait(120);
      const filename = buildQualityPdfFilename(`${toolKey}-${safePart(entry.title) || "report"}`);
      await exportElementToPdf(element, filename);
    } catch {
      setStatusText(copy.exportPdfError);
    }
  }

  function renameEntry(entry: SavedReport<T>) {
    const nextTitle = window.prompt(copy.renamePrompt, entry.title)?.trim();
    if (!nextTitle || nextTitle === entry.title) return;
    const now = new Date().toISOString();
    const next = savedReports.map((item) =>
      item.id === entry.id ? { ...item, title: nextTitle, updatedAt: now } : item,
    );
    persist(next);
    setStatusText(copy.renameSuccess);
  }

  function removeEntry(entry: SavedReport<T>) {
    if (!window.confirm(copy.deleteConfirm)) return;
    const next = savedReports.filter((item) => item.id !== entry.id);
    persist(next);
    setStatusText(copy.removeSuccess);
  }

  function loadEntry(entry: SavedReport<T>) {
    onLoadData(entry.data);
    setStatusText(copy.loadSuccess);
  }

  return (
    <>
      <section className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
        <div className="flex flex-wrap items-center gap-2">
          <button
            type="button"
            onClick={onDemoFill}
            data-testid="report-actions-demo"
            className="rounded-full border border-emerald-300 bg-emerald-50 px-3 py-1.5 text-[11px] font-semibold text-emerald-700 hover:bg-emerald-100"
          >
            {copy.demoFill}
          </button>
          <button
            type="button"
            onClick={openSaveModal}
            data-testid="report-actions-save"
            className="rounded-full border border-slate-300 bg-white px-3 py-1.5 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
          >
            {copy.save}
          </button>
          <button
            type="button"
            onClick={() => setIsManageModalOpen(true)}
            data-testid="report-actions-manage"
            className="rounded-full border border-slate-300 bg-white px-3 py-1.5 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
          >
            {copy.manage} ({savedReports.length})
          </button>
          <button
            type="button"
            onClick={exportCurrentPdf}
            data-testid="report-actions-export-pdf"
            className="rounded-full bg-slate-900 px-3 py-1.5 text-[11px] font-semibold text-white hover:bg-slate-800"
          >
            {copy.exportPdf}
          </button>
          <button
            type="button"
            onClick={onReset}
            data-testid="report-actions-reset"
            className="rounded-full border border-slate-300 bg-white px-3 py-1.5 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
          >
            {copy.reset}
          </button>
        </div>
        {statusText ? <p className="mt-2 text-[11px] text-slate-600">{statusText}</p> : null}
      </section>

      {isSaveModalOpen ? (
        <div
          className="fixed inset-0 z-[80] flex items-center justify-center bg-slate-900/40 p-4"
          data-testid="report-actions-save-modal"
        >
          <div className="w-full max-w-md rounded-2xl border border-slate-200 bg-white p-5 shadow-xl">
            <h3 className="text-sm font-semibold text-slate-900">{copy.saveModalTitle}</h3>
            <label className="mt-3 block space-y-1">
              <span className="block text-[11px] font-medium text-slate-700">{copy.saveTitleLabel}</span>
              <input
                type="text"
                value={titleInput}
                onChange={(event) = aria-label="Input field"> setTitleInput(event.target.value)}
                placeholder={copy.saveTitlePlaceholder}
                data-testid="report-actions-title-input"
                className="w-full rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
              />
            </label>
            <div className="mt-4 flex flex-wrap justify-end gap-2">
              <button
                type="button"
                onClick={() => setIsSaveModalOpen(false)}
                className="rounded-full border border-slate-300 bg-white px-3 py-1.5 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
              >
                {copy.cancel}
              </button>
              <button
                type="button"
                onClick={createSavedReport}
                data-testid="report-actions-save-confirm"
                className="rounded-full bg-slate-900 px-3 py-1.5 text-[11px] font-semibold text-white hover:bg-slate-800"
              >
                {copy.saveConfirm}
              </button>
            </div>
          </div>
        </div>
      ) : null}

      {isManageModalOpen ? (
        <div
          className="fixed inset-0 z-[80] flex items-center justify-center bg-slate-900/40 p-4"
          data-testid="report-actions-manage-modal"
        >
          <div className="w-full max-w-4xl rounded-2xl border border-slate-200 bg-white p-5 shadow-xl">
            <div className="mb-3 flex items-center justify-between gap-2">
              <h3 className="text-sm font-semibold text-slate-900">{copy.manageTitle}</h3>
              <button
                type="button"
                onClick={() => setIsManageModalOpen(false)}
                data-testid="report-actions-manage-close"
                className="rounded-full border border-slate-300 bg-white px-3 py-1.5 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
              >
                {copy.close}
              </button>
            </div>

            {savedReports.length === 0 ? (
              <p className="text-xs text-slate-600">{copy.emptySaved}</p>
            ) : (
              <div className="max-h-[70vh] space-y-3 overflow-y-auto pr-1">
                {savedReports.map((entry) => (
                  <div key={entry.id} className="rounded-xl border border-slate-200 bg-slate-50 p-3">
                    <div className="flex flex-wrap items-center justify-between gap-2">
                      <div>
                        <p className="text-sm font-semibold text-slate-900">{entry.title}</p>
                        <p className="text-[11px] text-slate-600">
                          {copy.createdAt}: {formatDateLabel(entry.createdAt)} | {copy.updatedAt}:{" "}
                          {formatDateLabel(entry.updatedAt)}
                        </p>
                      </div>
                      <div className="flex flex-wrap gap-2">
                        <button
                          type="button"
                          onClick={() => loadEntry(entry)}
                          data-testid="report-actions-load"
                          className="rounded-full border border-slate-300 bg-white px-3 py-1 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
                        >
                          {copy.load}
                        </button>
                        <button
                          type="button"
                          onClick={() => renameEntry(entry)}
                          data-testid="report-actions-rename"
                          className="rounded-full border border-slate-300 bg-white px-3 py-1 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
                        >
                          {copy.rename}
                        </button>
                        <button
                          type="button"
                          onClick={() => removeEntry(entry)}
                          data-testid="report-actions-delete"
                          className="rounded-full border border-rose-300 bg-rose-50 px-3 py-1 text-[11px] font-semibold text-rose-700 hover:bg-rose-100"
                        >
                          {copy.remove}
                        </button>
                        <button
                          type="button"
                          onClick={() => exportSavedPdf(entry)}
                          data-testid="report-actions-export-pdf-saved"
                          className="rounded-full border border-slate-300 bg-white px-3 py-1 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
                        >
                          {copy.exportPdf}
                        </button>
                        <button
                          type="button"
                          onClick={() => exportSavedJson(entry)}
                          data-testid="report-actions-export-json"
                          className="rounded-full border border-slate-300 bg-white px-3 py-1 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
                        >
                          {copy.exportJson}
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      ) : null}
    </>
  );
}

"use client";

import { useEffect, useRef } from "react";
import type { ChartConfiguration } from "chart.js";

type ChartModule = typeof import("chart.js");
type ChartInstance = import("chart.js").Chart;

let chartModulePromise: Promise<ChartModule> | null = null;
let chartRegistered = false;

const loadChartModule = async () => {
  chartModulePromise ??= import("chart.js");
  const chartModule = await chartModulePromise;

  if (!chartRegistered) {
    chartModule.Chart.register(
      chartModule.LineController,
      chartModule.LineElement,
      chartModule.PointElement,
      chartModule.LinearScale,
      chartModule.CategoryScale,
      chartModule.BarController,
      chartModule.BarElement,
      chartModule.Tooltip,
      chartModule.Legend,
    );
    chartRegistered = true;
  }

  return chartModule;
};

export type ChartDataset = {
  label: string;
  data: Array<number | { x: number; y: number }>;
  borderColor?: string;
  backgroundColor?: string;
  fill?: boolean;
};

export type ChartConfig = {
  type: "line" | "bar";
  labels?: Array<string | number>;
  datasets: ChartDataset[];
  xLabel?: string;
  yLabel?: string;
};

export default function ChartCanvas({ config, className = "" }: { config: ChartConfig; className?: string }) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const chartRef = useRef<ChartInstance | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    if (chartRef.current) {
      chartRef.current.destroy();
      chartRef.current = null;
    }

    const ctx = canvasRef.current.getContext("2d");
    if (!ctx) return;

    const chartConfig: ChartConfiguration = {
      type: config.type,
      data: {
        labels: config.labels,
        datasets: config.datasets.map((dataset) => ({
          ...dataset,
          borderWidth: 2,
          pointRadius: config.type === "line" ? 2 : 0,
        })),
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: true },
        },
        scales: {
          x: {
            type: config.type === "line" ? "linear" : "category",
            title: config.xLabel ? { display: true, text: config.xLabel } : undefined,
            ticks: { color: "#64748b" },
          },
          y: {
            title: config.yLabel ? { display: true, text: config.yLabel } : undefined,
            ticks: { color: "#64748b" },
          },
        },
      },
    };

    let cancelled = false;

    void (async () => {
      const { Chart } = await loadChartModule();
      if (cancelled) return;
      chartRef.current = new Chart(ctx, chartConfig);
    })();

    return () => {
      cancelled = true;
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
    };
  }, [config]);

  return <canvas ref={canvasRef} className={className} />;
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import ChartCanvas from "@/components/sanity-check/ChartCanvas";
import { runMonteCarlo } from "@/lib/sanityCheck/engine";
import type { LabSession, MonteCarloResult } from "@/lib/sanityCheck/types";

type MonteCarloCopy = {
  title: string;
  description: string;
  iterationsLabel: string;
  run: string;
  running: string;
  chartTitle: string;
  countLabel: string;
  statsTitle: string;
  mean: string;
  stdev: string;
  p05: string;
  p50: string;
  p95: string;
  empty: string;
};

type MonteCarloPanelProps = {
  session: LabSession;
  onSessionChange: (next: LabSession) => void;
  copy: MonteCarloCopy;
  locale: "tr" | "en";
};

const formatNumber = (value: number | null, locale: "tr" | "en") => {
  if (value === null) return "-";
  return new Intl.NumberFormat(locale === "en" ? "en-US" : "tr-TR", { maximumFractionDigits: 6 }).format(value);
};

export default function MonteCarloPanel({ session, onSessionChange, copy, locale }: MonteCarloPanelProps) {
  const [result, setResult] = useState<MonteCarloResult | null>(null);
  const [loading, setLoading] = useState(false);
  const workerRef = useRef<Worker | null>(null);

  useEffect(() => {
    return () => {
      if (workerRef.current) {
        workerRef.current.terminate();
        workerRef.current = null;
      }
    };
  }, []);

  const handleRun = () => {
    setLoading(true);

    if (typeof Worker !== "undefined") {
      try {
        if (!workerRef.current) {
          workerRef.current = new Worker(new URL("./monteCarloWorker.ts", import.meta.url));
        }
        workerRef.current.onmessage = (event) => {
          setResult(event.data as MonteCarloResult);
          setLoading(false);
        };
        workerRef.current.onerror = () => {
          setLoading(false);
        };
        workerRef.current.postMessage({ session });
        return;
      } catch {
        // fallback to main thread
      }
    }

    window.setTimeout(() => {
      const next = runMonteCarlo(session);
      setResult(next);
      setLoading(false);
    }, 0);
  };

  const histogramConfig = useMemo(() => {
    if (!result || result.histogram.length === 0) return null;
    return {
      type: "bar" as const,
      labels: result.histogram.map((bin) => `${bin.x0.toFixed(2)}-${bin.x1.toFixed(2)}`),
      datasets: [
        {
          label: copy.chartTitle,
          data: result.histogram.map((bin) => bin.count),
          backgroundColor: "rgba(16,185,129,0.4)",
          borderColor: "#10b981",
        },
      ],
      xLabel: copy.chartTitle,
      yLabel: copy.countLabel,
    };
  }, [copy.chartTitle, copy.countLabel, result]);

  return (
    <div className="space-y-3">
      <div className="space-y-1">
        <h3 className="text-sm font-semibold text-slate-900">{copy.title}</h3>
        <p className="text-xs text-slate-500">{copy.description}</p>
      </div>

      <div className="grid gap-3 sm:grid-cols-2">
        <div className="space-y-1">
          <label className="block text-[11px] font-semibold text-slate-600">{copy.iterationsLabel}</label>
          <input
            type="number"
            value={session.monteCarlo.iterations}
            min={100}
            max={10000}
            onChange={(event) = aria-label="Number input">
              onSessionChange({
                ...session,
                monteCarlo: { ...session.monteCarlo, iterations: Number(event.target.value) || 1000 },
              })
            }
            className="w-full rounded-lg border border-slate-300 px-2 py-1 text-xs"
          />
        </div>
        <div className="flex items-end">
          <button
            type="button"
            onClick={handleRun}
            disabled={loading}
            className="w-full rounded-full bg-slate-900 px-4 py-2 text-[11px] font-semibold text-white transition hover:bg-slate-800"
          >
            {loading ? copy.running : copy.run}
          </button>
        </div>
      </div>

      {result ? (
        <div className="grid gap-3 md:grid-cols-2">
          <div className="rounded-2xl border border-slate-200 bg-white p-3">
            <h4 className="text-xs font-semibold text-slate-700">{copy.statsTitle}</h4>
            <div className="mt-2 space-y-1 text-xs text-slate-600">
              <div className="flex items-center justify-between">
                <span>{copy.mean}</span>
                <span className="font-semibold text-slate-900">{formatNumber(result.stats.mean, locale)}</span>
              </div>
              <div className="flex items-center justify-between">
                <span>{copy.stdev}</span>
                <span className="font-semibold text-slate-900">{formatNumber(result.stats.stdev, locale)}</span>
              </div>
              <div className="flex items-center justify-between">
                <span>{copy.p05}</span>
                <span className="font-semibold text-slate-900">{formatNumber(result.stats.p05, locale)}</span>
              </div>
              <div className="flex items-center justify-between">
                <span>{copy.p50}</span>
                <span className="font-semibold text-slate-900">{formatNumber(result.stats.p50, locale)}</span>
              </div>
              <div className="flex items-center justify-between">
                <span>{copy.p95}</span>
                <span className="font-semibold text-slate-900">{formatNumber(result.stats.p95, locale)}</span>
              </div>
            </div>
          </div>

          <div className="rounded-2xl border border-slate-200 bg-white p-3">
            <h4 className="text-xs font-semibold text-slate-700">{copy.chartTitle}</h4>
            <div className="mt-2 h-48">
              {histogramConfig ? (
                <ChartCanvas config={histogramConfig} className="h-full w-full" />
              ) : (
                <div className="rounded-xl border border-dashed border-slate-200 bg-slate-50 p-4 text-xs text-slate-500">
                  {copy.empty}
                </div>
              )}
            </div>
          </div>
        </div>
      ) : (
        <div className="rounded-2xl border border-dashed border-slate-200 bg-slate-50 p-4 text-xs text-slate-500">
          {copy.empty}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import dynamic from "next/dynamic";
import { useSearchParams } from "next/navigation";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { getMessages } from "@/utils/messages";
import { evaluateFormula } from "@/lib/sanityCheck/engine";
import type { LabSession } from "@/lib/sanityCheck/types";
import { decodeSession, encodeSession } from "@/lib/sanityCheck/share";
import {
  deleteSavedSession,
  readLastSession,
  readSavedSessions,
  saveSession,
  writeLastSession,
  type SavedSession,
} from "@/lib/sanityCheck/storage";
import VariableTable from "@/components/sanity-check/VariableTable";
import FormulaEditor from "@/components/sanity-check/FormulaEditor";
import ResultPanel from "@/components/sanity-check/ResultPanel";
import ClientErrorBoundary from "@/components/sanity-check/ClientErrorBoundary";
import AISummaryPanel from "@/src/components/ai/AISummaryPanel";
import ToolFavoriteButton from "@/components/tools/ToolFavoriteButtonLazy";
import ToolDataActions from "@/components/tools/ToolDataActions";
import AdvisorPanel from "@/src/components/tools/AdvisorPanel";
import { getAdvisorInsights } from "@/src/lib/advisor/engine";
import { addRecent } from "@/utils/tool-storage";
import { withLocalePrefix } from "@/utils/locale-path";

const UNIT_OPTIONS = [
  "",
  "N",
  "kN",
  "N m",
  "Pa",
  "kPa",
  "MPa",
  "bar",
  "m",
  "mm",
  "cm",
  "kg",
  "s",
  "rad/s",
  "rpm",
  "W",
  "kW",
  "J",
  "Hz",
];

const SweepPanel = dynamic(() => import("@/components/sanity-check/SweepPanel"), {
  loading: () => <PanelLoadingState />,
});

const MonteCarloPanel = dynamic(() => import("@/components/sanity-check/MonteCarloPanel"), {
  loading: () => <PanelLoadingState />,
});

const buildDefaultSession = (locale: "tr" | "en"): LabSession => ({
  title: "",
  variables: [
    {
      id: "var-t",
      symbol: "T",
      name: locale === "tr" ? "Tork" : "Torque",
      description: locale === "tr" ? "Giriş torku" : "Input torque",
      value: 12,
      unit: "N m",
      min: 10,
      max: 14,
      distribution: "normal",
    },
    {
      id: "var-w",
      symbol: "w",
      name: locale === "tr" ? "Açısal hız" : "Angular speed",
      description: locale === "tr" ? "Açısal hız" : "Angular speed",
      value: 120,
      unit: "rad/s",
      min: 80,
      max: 150,
      distribution: "normal",
    },
  ],
  formula: "P = T * w",
  expectedUnit: "W",
  sweep: {
    variableId: "var-t",
    points: 50,
  },
  monteCarlo: {
    iterations: 1000,
  },
});

type TabKey = "sweep" | "monteCarlo";

export default function SanityCheckLab() {
  const { locale } = useLocale();
  const messages = getMessages(locale);
  const pageCopy = messages.pages.sanityCheck;
  const copy = messages.components.sanityCheck;
  const searchParams = useSearchParams();

  const defaultSession = useMemo(() => buildDefaultSession(locale), [locale]);
  const [session, setSession] = useState<LabSession>(() => defaultSession);
  const [activeTab, setActiveTab] = useState<TabKey>("sweep");
  const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);
  const [selectedSessionId, setSelectedSessionId] = useState<string>("");
  const [statusMessage, setStatusMessage] = useState<string>("");
  const initialLoadRef = useRef(false);

  const result = useMemo(() => evaluateFormula(session), [session]);
  const reportUrl = useMemo(() => {
    const encoded = encodeSession(session);
    if (!encoded) return undefined;
    const reportPath = withLocalePrefix("/tools/sanity-check/report", locale);
    return `${reportPath}?session=${encoded}`;
  }, [session, locale]);
  const advisorInsights = useMemo(
    () => getAdvisorInsights("sanity-check", { session, result }, { locale, reportUrl }),
    [session, result, locale, reportUrl],
  );

  useEffect(() => {
    addRecent("sanity-check");
  }, []);

  const handleSessionTitle = (value: string) => setSession((prev) => ({ ...prev, title: value }));

  useEffect(() => {
    if (initialLoadRef.current) return;
    initialLoadRef.current = true;

    const shared = searchParams?.get("session");
    if (shared) {
      const decoded = decodeSession(shared);
      if (decoded) {
        Promise.resolve().then(() => {
          setSession(decoded);
          setStatusMessage(copy.session.restoreNotice);
        });
      }
    } else {
      const last = readLastSession();
      if (last) {
        Promise.resolve().then(() => setSession(last));
      }
    }

    const nextSaved = readSavedSessions();
    Promise.resolve().then(() => setSavedSessions(nextSaved));
  }, [copy.session.restoreNotice, searchParams]);

  useEffect(() => {
    const id = window.setTimeout(() => writeLastSession(session), 300);
    return () => window.clearTimeout(id);
  }, [session]);

  const handleSave = (forceNew: boolean) => {
    const title = session.title?.trim() || copy.session.untitled;
    const entry = saveSession(session, title, forceNew ? undefined : selectedSessionId || undefined);
    setSavedSessions(readSavedSessions());
    setSelectedSessionId(entry.id);
    setStatusMessage(`${copy.session.lastSaved}: ${entry.updatedAt}`);
  };

  const handleLoad = () => {
    const selected = savedSessions.find((item) => item.id === selectedSessionId);
    if (!selected) return;
    setSession(selected.session);
    setStatusMessage(`${copy.session.lastSaved}: ${selected.updatedAt}`);
  };

  const handleDelete = () => {
    if (!selectedSessionId) return;
    const next = deleteSavedSession(selectedSessionId);
    setSavedSessions(next);
    setSelectedSessionId("");
  };

  const handleShare = async () => {
    const encoded = encodeSession(session);
    if (!encoded) return;
    const sharePath = withLocalePrefix("/tools/sanity-check", locale);
    const url = `${window.location.origin}${sharePath}?session=${encoded}`;
    try {
      await navigator.clipboard.writeText(url);
      setStatusMessage(copy.session.shareCopied);
    } catch {
      setStatusMessage(copy.session.shareFailed);
    }
  };

  const handleExport = () => {
    const encoded = encodeSession(session);
    if (!encoded) return;
    const reportPath = withLocalePrefix("/tools/sanity-check/report", locale);
    window.open(`${reportPath}?session=${encoded}`, "_blank");
  };

  const errorFallback = (
    <div className="rounded-3xl border border-amber-200 bg-amber-50 p-6 text-slate-900">
      <h2 className="text-lg font-semibold">{copy.errorBoundary.title}</h2>
      <p className="mt-2 text-sm text-slate-700">{copy.errorBoundary.description}</p>
      <button
        type="button"
        onClick={() => window.location.reload()}
        className="mt-4 rounded-full bg-slate-900 px-4 py-2 text-xs font-semibold text-white"
      >
        {copy.errorBoundary.cta}
      </button>
    </div>
  );

  return (
    <ClientErrorBoundary fallback={errorFallback}>
      <div className="space-y-6">
      <section className="rounded-3xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
          <div className="space-y-2">
            <div className="inline-flex items-center gap-2 rounded-full border border-slate-200 bg-slate-50 px-3 py-1 text-[11px] font-semibold text-slate-600">
              {pageCopy.badge}
            </div>
            <h1 className="text-balance text-2xl font-semibold text-slate-900 md:text-3xl">{pageCopy.title}</h1>
            <p className="text-sm text-slate-600">{pageCopy.description}</p>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            <div className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-600">
              {copy.session.titleLabel}
            </div>
            <input
              value={session.title ?? ""}
              onChange={(event) = aria-label="Input field"> handleSessionTitle(event.target.value)}
              className="rounded-full border border-slate-200 px-3 py-1 text-[11px]"
              placeholder={copy.session.titleLabel}
              aria-label={copy.session.titleLabel}
            />
            <ToolFavoriteButton toolId="sanity-check" toolTitle={pageCopy.title} size="sm" />
            <button
              type="button"
              onClick={() => handleSave(false)}
              className="rounded-full bg-slate-900 px-3 py-1 text-[11px] font-semibold text-white"
            >
              {copy.session.save}
            </button>
            <button
              type="button"
              onClick={() => handleSave(true)}
              className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-700"
            >
              {copy.session.saveAs}
            </button>
            <button
              type="button"
              onClick={handleShare}
              className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-700"
            >
              {copy.session.share}
            </button>
            <button
              type="button"
              onClick={handleExport}
              className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-700"
            >
              {copy.session.export}
            </button>
          </div>
        </div>
        <div className="mt-4 flex flex-wrap items-center gap-2 text-[11px] text-slate-500">
          <span className="rounded-full border border-slate-200 px-3 py-1 text-[10px] font-semibold text-slate-600">
            {copy.session.savedTitle}
          </span>
          <select
            value={selectedSessionId}
            onChange={(event) = aria-label="Select field"> setSelectedSessionId(event.target.value)}
            className="rounded-full border border-slate-200 px-3 py-1 text-[11px]"
          >
            <option value="">{copy.session.savedTitle}</option>
            {savedSessions.map((item) => (
              <option key={item.id} value={item.id}>
                {item.title}
              </option>
            ))}
          </select>
          <button
            type="button"
            onClick={handleLoad}
            className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-600"
          >
            {copy.session.load}
          </button>
          <button
            type="button"
            onClick={handleDelete}
            className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-600"
          >
            {copy.session.delete}
          </button>
          {statusMessage ? <span className="text-[11px] text-slate-500">{statusMessage}</span> : null}
        </div>
      </section>

      <section className="rounded-3xl border border-slate-200 bg-white p-5 shadow-sm">
        <div className="space-y-2">
          <h2 className="text-sm font-semibold text-slate-900">{pageCopy.howToTitle}</h2>
          <div className="grid gap-3 md:grid-cols-3">
            {pageCopy.howToSteps.map((step: string, index: number) => (
              <div key={step} className="rounded-2xl border border-slate-200 bg-slate-50 p-3 text-xs text-slate-600">
                <div className="mb-1 text-[10px] font-semibold uppercase tracking-wide text-slate-500">
                  {index + 1}
                </div>
                {step}
              </div>
            ))}
          </div>
        </div>
      </section>

      <div className="grid gap-6 lg:grid-cols-[minmax(0,1.1fr)_minmax(0,0.9fr)]">
        <div className="space-y-4">
          <VariableTable
            variables={session.variables}
            onChange={(variables) => setSession((prev) => ({ ...prev, variables }))}
            copy={copy.variableTable}
          />
          <FormulaEditor
            formula={session.formula}
            onChange={(formula) => setSession((prev) => ({ ...prev, formula }))}
            copy={copy.formulaEditor}
          />
        </div>

        <div className="space-y-4">
          <ResultPanel
            result={result}
            expectedUnit={session.expectedUnit ?? ""}
            onExpectedUnitChange={(value) => setSession((prev) => ({ ...prev, expectedUnit: value }))}
            copy={copy.resultPanel}
            locale={locale}
          />
          <ToolDataActions
            toolSlug="sanity-check"
            toolTitle={pageCopy.title}
            inputs={{
              formula: session.formula,
              expectedUnit: session.expectedUnit ?? "",
              ...Object.fromEntries(session.variables.map((variable) => [variable.symbol, variable.value])),
            }}
            outputs={result ? { value: result.value ?? null, unit: result.unit } : null}
            reportUrl={reportUrl}
          />

          {!result.error ? (
            <AISummaryPanel
              locale={locale}
              toolId="sanity-check"
              toolName={pageCopy.title}
              inputs={{
                formula: session.formula,
                expectedUnit: session.expectedUnit ?? "",
                variables: session.variables.map((variable) => ({
                  symbol: variable.symbol,
                  value: variable.value,
                  unit: variable.unit ?? "",
                })),
              }}
              outputs={{
                value: result.value,
                unit: result.unit,
                warnings: result.warnings.map((warning) => warning.type),
              }}
            />
          ) : null}
          <AdvisorPanel insights={advisorInsights} />

          <section className="rounded-2xl border border-slate-200 bg-white shadow-sm">
            <div className="sticky top-2 z-10 flex gap-2 border-b border-slate-200 bg-white/90 px-4 py-3 backdrop-blur">
              <button
                type="button"
                onClick={() => setActiveTab("sweep")}
                className={`rounded-full px-3 py-1 text-[11px] font-semibold ${
                  activeTab === "sweep"
                    ? "bg-slate-900 text-white"
                    : "border border-slate-200 text-slate-600"
                }`}
              >
                {pageCopy.tabs.sweep}
              </button>
              <button
                type="button"
                onClick={() => setActiveTab("monteCarlo")}
                className={`rounded-full px-3 py-1 text-[11px] font-semibold ${
                  activeTab === "monteCarlo"
                    ? "bg-slate-900 text-white"
                    : "border border-slate-200 text-slate-600"
                }`}
              >
                {pageCopy.tabs.monteCarlo}
              </button>
            </div>
            <div className="p-4">
              {activeTab === "sweep" ? (
                <SweepPanel
                  session={session}
                  onSessionChange={setSession}
                  copy={copy.sweepPanel}
                />
              ) : (
                <MonteCarloPanel
                  session={session}
                  onSessionChange={setSession}
                  copy={copy.monteCarloPanel}
                  locale={locale}
                />
              )}
            </div>
          </section>
        </div>
      </div>

        <datalist id="sanity-units">
          {UNIT_OPTIONS.filter(Boolean).map((unit) => (
            <option key={unit} value={unit} />
          ))}
        </datalist>
      </div>
    </ClientErrorBoundary>
  );
}

function PanelLoadingState() {
  return <div className="rounded-2xl border border-slate-200 bg-slate-50 px-4 py-6 text-xs text-slate-500">Loading...</div>;
}

"use client";

import { useMemo, useState } from "react";
import ChartCanvas from "@/components/sanity-check/ChartCanvas";
import { runSweep } from "@/lib/sanityCheck/engine";
import type { LabSession, SweepResult } from "@/lib/sanityCheck/types";

const buildAxisLabel = (label: string, unit: string) => (unit ? `${label} (${unit})` : label);

type SweepPanelCopy = {
  title: string;
  description: string;
  variableLabel: string;
  pointsLabel: string;
  run: string;
  chartTitle: string;
  resultLabel: string;
  empty: string;
  rangeMissing: string;
};

type SweepPanelProps = {
  session: LabSession;
  onSessionChange: (next: LabSession) => void;
  copy: SweepPanelCopy;
};

export default function SweepPanel({ session, onSessionChange, copy }: SweepPanelProps) {
  const [result, setResult] = useState<SweepResult | null>(null);

  const variables = session.variables;
  const selectedId = session.sweep.variableId ?? variables[0]?.id;
  const selectedVar = variables.find((variable) => variable.id === selectedId);

  const handleRun = () => {
    const next = runSweep(session, selectedId);
    setResult(next);
  };

  const chartConfig = useMemo(() => {
    if (!result || result.points.length === 0) return null;
    return {
      type: "line" as const,
      datasets: [
        {
          label: copy.chartTitle,
          data: result.points.map((point) => ({ x: point.x, y: point.y })),
          borderColor: "#0ea5e9",
          backgroundColor: "rgba(14,165,233,0.2)",
        },
      ],
      xLabel: buildAxisLabel(selectedVar?.symbol ?? "x", result.xUnit),
      yLabel: buildAxisLabel(copy.resultLabel, result.yUnit),
    };
  }, [copy.chartTitle, copy.resultLabel, result, selectedVar]);

  return (
    <div className="space-y-3">
      <div className="space-y-1">
        <h3 className="text-sm font-semibold text-slate-900">{copy.title}</h3>
        <p className="text-xs text-slate-500">{copy.description}</p>
      </div>

      <div className="grid gap-3 sm:grid-cols-2">
        <div className="space-y-1">
          <label className="block text-[11px] font-semibold text-slate-600">{copy.variableLabel}</label>
          <select
            value={selectedId ?? ""}
            onChange={(event) = aria-label="Select field">
              onSessionChange({
                ...session,
                sweep: { ...session.sweep, variableId: event.target.value },
              })
            }
            className="w-full rounded-lg border border-slate-300 px-2 py-1 text-xs"
          >
            {variables.map((variable) => (
              <option key={variable.id} value={variable.id}>
                {variable.symbol} - {variable.name}
              </option>
            ))}
          </select>
        </div>
        <div className="space-y-1">
          <label className="block text-[11px] font-semibold text-slate-600">{copy.pointsLabel}</label>
          <input
            type="number"
            value={session.sweep.points}
            min={2}
            max={200}
            onChange={(event) = aria-label="Number input">
              onSessionChange({
                ...session,
                sweep: { ...session.sweep, points: Number(event.target.value) || 50 },
              })
            }
            className="w-full rounded-lg border border-slate-300 px-2 py-1 text-xs"
          />
        </div>
      </div>

      <button
        type="button"
        onClick={handleRun}
        className="rounded-full bg-slate-900 px-4 py-2 text-[11px] font-semibold text-white transition hover:bg-slate-800"
      >
        {copy.run}
      </button>

      {result?.error ? (
        <div className="rounded-xl border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-700">
          {copy.rangeMissing}
        </div>
      ) : null}

      {chartConfig ? (
        <div className="rounded-2xl border border-slate-200 bg-white p-3">
          <div className="h-56">
            <ChartCanvas config={chartConfig} className="h-full w-full" />
          </div>
        </div>
      ) : (
        <div className="rounded-2xl border border-dashed border-slate-200 bg-slate-50 p-4 text-xs text-slate-500">
          {copy.empty}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState, type KeyboardEvent as ReactKeyboardEvent } from "react";
import { useRouter } from "next/navigation";
import { BookOpen, Bookmark, Compass, FileText, Scale, Wrench } from "lucide-react";
import { useSearchIndex, filterSearchResults } from "@/components/search/useSearchIndex";
import { COMMAND_PALETTE_OPEN_EVENT } from "@/components/search/commandPaletteEvents";
import { useDebouncedValue } from "@/components/search/useDebouncedValue";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { localePath } from "@/utils/locale-path";
import type { SearchIndexItem } from "@/utils/search-index";
import type { Messages } from "@/utils/messages";

const ICONS = {
  tool: Wrench,
  standard: Scale,
  reference: Bookmark,
  blog: FileText,
  guide: Compass,
  glossary: BookOpen,
} as const;

const BADGE_STYLES: Record<SearchIndexItem["type"], string> = {
  tool: "border-emerald-200 bg-emerald-50 text-emerald-700",
  standard: "border-sky-200 bg-sky-50 text-sky-700",
  reference: "border-sky-200 bg-sky-50 text-sky-700",
  blog: "border-amber-200 bg-amber-50 text-amber-700",
  guide: "border-teal-200 bg-teal-50 text-teal-700",
  glossary: "border-slate-200 bg-slate-50 text-slate-700",
};

type CommandPaletteProps = {
  copy: Messages["components"]["search"];
};

export default function CommandPalette({ copy }: CommandPaletteProps) {
  const { locale } = useLocale();
  const router = useRouter();
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [activeIndex, setActiveIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const debouncedQuery = useDebouncedValue(query, 100);
  const { items, loading } = useSearchIndex(open);

  const results = useMemo(() => {
    if (!open) return [];
    return filterSearchResults(items, debouncedQuery, 20);
  }, [items, debouncedQuery, open]);

  useEffect(() => {
    if (!open) return;
    inputRef.current?.focus();
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = "";
    };
  }, [open]);

  useEffect(() => {
    const openPalette = () => {
      setOpen(true);
      setQuery("");
      setActiveIndex(0);
    };

    const handler = (event: KeyboardEvent) => {
      if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === "k") {
        event.preventDefault();
        openPalette();
      } else if (event.key === "Escape") {
        setOpen(false);
      }
    };

    window.addEventListener("keydown", handler);
    window.addEventListener(COMMAND_PALETTE_OPEN_EVENT, openPalette);
    return () => {
      window.removeEventListener("keydown", handler);
      window.removeEventListener(COMMAND_PALETTE_OPEN_EVENT, openPalette);
    };
  }, []);

  const handleNavigate = (item: SearchIndexItem) => {
    setOpen(false);
    router.push(localePath(locale, item.href));
  };

  const handleInputKey = (event: ReactKeyboardEvent<HTMLInputElement>) => {
    if (event.key === "ArrowDown") {
      event.preventDefault();
      setActiveIndex((prev) => Math.min(prev + 1, results.length - 1));
    } else if (event.key === "ArrowUp") {
      event.preventDefault();
      setActiveIndex((prev) => Math.max(prev - 1, 0));
    } else if (event.key === "Enter" && results[activeIndex]) {
      event.preventDefault();
      handleNavigate(results[activeIndex]);
    }
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-[120] flex items-start justify-center px-4 py-16" data-testid="command-palette">
      <button
        type="button"
        className="absolute inset-0 bg-slate-900/50"
        aria-label={copy.paletteOpen}
        onClick={() => setOpen(false)}
      />
      <div className="relative w-full max-w-2xl overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-2xl">
        <div className="border-b border-slate-200 bg-slate-50 px-5 py-4">
          <div className="flex items-center justify-between gap-3">
            <div>
              <p className="text-xs font-semibold uppercase tracking-[0.2em] text-emerald-600">{copy.paletteTitle}</p>
              <p className="text-xs text-slate-500">{copy.paletteHint}</p>
            </div>
            <span className="rounded-full border border-slate-200 bg-white px-3 py-1 text-[10px] font-semibold text-slate-500">
              Ctrl/Cmd + K
            </span>
          </div>
          <input
            ref={inputRef}
            type="search"
            value={query}
            onChange={(event) = aria-label="Search input"> {
              setQuery(event.target.value);
              setActiveIndex(0);
            }}
            onKeyDown={handleInputKey}
            placeholder={copy.palettePlaceholder}
            className="mt-3 w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-900 outline-none focus:border-emerald-300 focus:ring-2 focus:ring-emerald-100"
            data-testid="command-palette-input"
          />
        </div>

        <div className="max-h-[420px] overflow-y-auto p-4">
          {loading ? (
            <p className="text-sm text-slate-500">...</p>
          ) : query.trim().length === 0 ? (
            <p className="text-sm text-slate-500">{copy.paletteHint}</p>
          ) : results.length === 0 ? (
            <p className="text-sm text-slate-500">{copy.paletteEmpty}</p>
          ) : (
            <ul className="space-y-2">
              {results.map((item, index) => {
                const Icon = ICONS[item.type];
                const active = index === activeIndex;
                return (
                  <li key={item.id}>
                    <button
                      type="button"
                      onClick={() => handleNavigate(item)}
                      className={`flex w-full items-center justify-between gap-4 rounded-2xl border px-4 py-3 text-left text-sm transition ${
                        active ? "border-emerald-300 bg-emerald-50/60" : "border-slate-200 bg-white hover:border-slate-300"
                      }`}
                      data-testid="command-palette-result"
                    >
                      <div className="flex items-center gap-3">
                        <span className="flex h-9 w-9 items-center justify-center rounded-xl bg-slate-100 text-slate-600">
                          <Icon className="h-4 w-4" />
                        </span>
                        <div className="space-y-1">
                          <p className="font-semibold text-slate-900">{item.title}</p>
                          {item.description ? (
                            <p className="text-xs text-slate-600">{item.description}</p>
                          ) : null}
                        </div>
                      </div>
                      <span
                        className={`shrink-0 rounded-full border px-2 py-1 text-[10px] font-semibold ${BADGE_STYLES[item.type]}`}
                      >
                        {copy.typeLabels[item.type]}
                      </span>
                    </button>
                  </li>
                );
              })}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { useMemo, useState } from "react";
import { BookOpen, Bookmark, Compass, FileText, Scale, Wrench } from "lucide-react";
import { useSearchIndex, filterSearchResults } from "@/components/search/useSearchIndex";
import { useDebouncedValue } from "@/components/search/useDebouncedValue";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { getMessages } from "@/utils/messages";
import { buildSearchText } from "@/utils/search-index";
import { withLocalePrefix } from "@/utils/locale-path";
import { getToolCopy, toolCatalog } from "@/tools/_shared/catalog";
import type { SearchIndexItem } from "@/utils/search-index";

const ICONS = {
  tool: Wrench,
  standard: Scale,
  reference: Bookmark,
  blog: FileText,
  guide: Compass,
  glossary: BookOpen,
} as const;

const BADGE_STYLES: Record<SearchIndexItem["type"], string> = {
  tool: "border-emerald-200 bg-emerald-50 text-emerald-700",
  standard: "border-sky-200 bg-sky-50 text-sky-700",
  reference: "border-sky-200 bg-sky-50 text-sky-700",
  blog: "border-amber-200 bg-amber-50 text-amber-700",
  guide: "border-teal-200 bg-teal-50 text-teal-700",
  glossary: "border-slate-200 bg-slate-50 text-slate-700",
};

export default function InlineSearch() {
  const { locale } = useLocale();
  const copy = getMessages(locale).components.search;
  const toolLibraryLabels = getMessages(locale).components.toolLibrary.labels;
  const toolLibraryLabelsEn = getMessages("en").components.toolLibrary.labels;
  const toolLibraryLabelsTr = getMessages("tr").components.toolLibrary.labels;
  const [query, setQuery] = useState("");
  const searchEnabled = query.trim().length > 0;
  const { items, loading } = useSearchIndex(searchEnabled);
  const debouncedQuery = useDebouncedValue(query, 100);
  const fallbackItems = useMemo<SearchIndexItem[]>(
    () =>
      toolCatalog.map((tool) => {
        const localized = getToolCopy(tool, locale);
        const english = getToolCopy(tool, "en");
        const turkish = getToolCopy(tool, "tr");
        const localizedCategory = tool.category ? toolLibraryLabels.category[tool.category] : "";
        const englishCategory = tool.category ? toolLibraryLabelsEn.category[tool.category] : "";
        const turkishCategory = tool.category ? toolLibraryLabelsTr.category[tool.category] : "";
        const localizedTagLabels = (tool.tags ?? []).map((tag) => toolLibraryLabels.tag[tag]);
        const englishTagLabels = (tool.tags ?? []).map((tag) => toolLibraryLabelsEn.tag[tag]);
        const turkishTagLabels = (tool.tags ?? []).map((tag) => toolLibraryLabelsTr.tag[tag]);

        return {
          id: `tool:${tool.id}`,
          type: "tool",
          title: localized.title,
          description: localized.description,
          href: withLocalePrefix(tool.href, locale),
          tags: [...(tool.tags ?? []), ...localizedTagLabels, ...englishTagLabels, ...turkishTagLabels],
          localeTitles: {
            tr: turkish.title,
            en: english.title,
          },
          searchText: buildSearchText(
            localized.title,
            localized.description,
            english.title,
            english.description,
            turkish.title,
            turkish.description,
            localizedCategory,
            englishCategory,
            turkishCategory,
            ...localizedTagLabels,
            ...englishTagLabels,
            ...turkishTagLabels,
            ...(tool.tags ?? []),
            tool.id,
            tool.type,
          ),
        };
      }),
    [locale, toolLibraryLabels, toolLibraryLabelsEn, toolLibraryLabelsTr],
  );
  const searchableItems = items.length > 0 ? items : fallbackItems;
  const showLoading = loading && items.length === 0 && fallbackItems.length === 0 && query.trim().length > 0;
  const results = useMemo(
    () => (searchEnabled ? filterSearchResults(searchableItems, debouncedQuery, 8) : []),
    [searchableItems, debouncedQuery, searchEnabled],
  );

  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm" data-testid="inline-search">
      <div className="space-y-2">
        <p className="text-xs font-semibold uppercase tracking-[0.2em] text-emerald-600">{copy.inlineTitle}</p>
        <p className="text-sm text-slate-600">{copy.inlineDescription}</p>
      </div>
      <div className="mt-4">
        <label className="text-xs font-semibold text-slate-700" htmlFor="tools-global-search">
          {copy.inlineTitle}
        </label>
        <input
          id="tools-global-search"
          type="search"
          value={query}
          onChange={(event) = aria-label="tools-global-search"> setQuery(event.target.value)}
          placeholder={copy.inlinePlaceholder}
          className="mt-2 w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-900 outline-none transition focus:border-emerald-300 focus:ring-2 focus:ring-emerald-100"
        />
      </div>

      <div className="mt-4">
        {showLoading ? (
          <p className="text-sm text-slate-500">{copy.inlineLoading}</p>
        ) : query.trim().length === 0 ? null : results.length === 0 ? (
          <p className="text-sm text-slate-500">{copy.inlineEmpty}</p>
        ) : (
          <div className="space-y-2">
            {results.map((item) => {
              const Icon = ICONS[item.type];
              return (
                <Link
                  key={item.id}
                  href={item.href}
                  prefetch={false}
                  className="flex items-center justify-between gap-4 rounded-2xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm transition hover:border-emerald-300 hover:bg-white"
                >
                  <div className="flex items-center gap-3">
                    <span className="flex h-9 w-9 items-center justify-center rounded-xl bg-white text-slate-600 shadow-sm">
                      <Icon className="h-4 w-4" />
                    </span>
                    <div className="space-y-1">
                      <p className="font-semibold text-slate-900">{item.title}</p>
                      {item.description ? (
                        <p className="text-xs text-slate-600">{item.description}</p>
                      ) : null}
                    </div>
                  </div>
                  <span
                    className={`shrink-0 rounded-full border px-2 py-1 text-[10px] font-semibold ${BADGE_STYLES[item.type]}`}
                  >
                    {copy.typeLabels[item.type]}
                  </span>
                </Link>
              );
            })}
          </div>
        )}
      </div>
    </section>
  );
}

"use client";

import { useMemo, useRef, useState, useEffect } from "react";
import type { StandardsTable as StandardsTableType, LocalizedText } from "@/data/standards";
import StandardsTable from "@/components/standards/StandardsTable";
import StandardsTableWrapper from "@/components/standards/StandardsTableWrapper";

type EnhancedStandardsTableProps = {
  table: StandardsTableType;
  rows: Array<Record<string, unknown>>;
  locale: "tr" | "en";
  exportLabel: string;
  emptyLabel: string;
};

const isLocalized = (value: unknown): value is LocalizedText =>
  Boolean(value && typeof value === "object" && "tr" in value && "en" in value);

const formatValue = (value: unknown, locale: "tr" | "en") => {
  if (value === null || value === undefined || value === "") return "-";
  if (typeof value === "number" && Number.isFinite(value)) {
    return value.toLocaleString(locale === "tr" ? "tr-TR" : "en-US", {
      maximumFractionDigits: 4,
    });
  }
  if (isLocalized(value)) return value[locale];
  return String(value);
};

export default function EnhancedStandardsTable({
  table,
  rows,
  locale,
  exportLabel,
  emptyLabel,
}: EnhancedStandardsTableProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [visibleColumnKeys, setVisibleColumnKeys] = useState<string[]>(() => table.columns.map((column) => column.key));
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (!dropdownRef.current) return;
      if (event.target instanceof Node && !dropdownRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const visibleColumns = useMemo(() => {
    const keySet = new Set(visibleColumnKeys);
    return table.columns.filter((column) => keySet.has(column.key));
  }, [table.columns, visibleColumnKeys]);

  const filteredTable = useMemo(
    () => ({
      ...table,
      columns: visibleColumns,
    }),
    [table, visibleColumns],
  );

  const toggleColumn = (key: string) => {
    setVisibleColumnKeys((current) => {
      if (current.includes(key)) {
        if (current.length === 1) return current;
        return current.filter((columnKey) => columnKey !== key);
      }

      const next = [...current, key];
      const order = new Map(table.columns.map((column, index) => [column.key, index]));
      return next.sort((a, b) => (order.get(a) ?? 0) - (order.get(b) ?? 0));
    });
  };

  const columnSelectorLabel = locale === "tr" ? "Kolonlar" : "Columns";
  const columnSelectorHelper =
    locale === "tr" ? "Görünür kolonları seçin" : "Select visible columns";

  return (
    <div className="space-y-3">
      <div className="flex justify-end">
        <div ref={dropdownRef} className="relative">
          <button
            type="button"
            onClick={() => setIsOpen((current) => !current)}
            className="inline-flex items-center gap-2 rounded-full border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-700 transition hover:border-slate-300"
            aria-haspopup="menu"
            aria-expanded={isOpen}
          >
            <span>{columnSelectorLabel}</span>
            <span className="rounded-full bg-slate-100 px-1.5 py-0.5 text-[10px] text-slate-600">
              {visibleColumns.length}/{table.columns.length}
            </span>
          </button>

          {isOpen ? (
            <div
              className="absolute right-0 z-30 mt-2 w-64 rounded-2xl border border-slate-200 bg-white p-3 shadow-lg"
              role="menu"
              aria-label={columnSelectorHelper}
            >
              <p className="mb-2 text-[11px] font-semibold uppercase tracking-wide text-slate-500">{columnSelectorHelper}</p>
              <div className="space-y-2">
                {table.columns.map((column) => {
                  const checked = visibleColumnKeys.includes(column.key);
                  const disableUncheck = checked && visibleColumnKeys.length === 1;

                  return (
                    <label key={`${table.id}-column-${column.key}`} className="flex items-center gap-2 text-xs text-slate-700">
                      <input
                        type="checkbox"
                        checked={checked}
                        onChange={() = aria-label="Checkbox"> toggleColumn(column.key)}
                        disabled={disableUncheck}
                        className="h-4 w-4 rounded border-slate-300 text-emerald-600 focus:ring-emerald-200 disabled:cursor-not-allowed disabled:opacity-50"
                      />
                      <span>{column.label[locale]}</span>
                    </label>
                  );
                })}
              </div>
            </div>
          ) : null}
        </div>
      </div>

      <StandardsTableWrapper hintLabel={locale === "tr" ? "← kaydır →" : "← scroll →"}>
        <div className="[&_[data-standards-table-scroll]]:hidden md:[&_[data-standards-table-scroll]]:block md:[&_[data-standards-table-scroll]]:max-h-[70vh] md:[&_[data-standards-table-scroll]]:overflow-y-auto md:[&_[data-standards-table-scroll]_thead_th]:sticky md:[&_[data-standards-table-scroll]_thead_th]:top-0 md:[&_[data-standards-table-scroll]_thead_th]:z-10 md:[&_[data-standards-table-scroll]_thead_th]:bg-slate-50">
          <StandardsTable
            table={filteredTable}
            rows={rows}
            locale={locale}
            exportLabel={exportLabel}
            emptyLabel={emptyLabel}
          />
        </div>
      </StandardsTableWrapper>

      {rows.length > 0 ? (
        <div className="space-y-3 md:hidden">
          {rows.map((row, rowIndex) => (
            <article
              key={`${table.id}-card-${rowIndex}`}
              className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm"
            >
              <div className="space-y-2">
                {visibleColumns.map((column) => (
                  <div
                    key={`${table.id}-card-${rowIndex}-${column.key}`}
                    className="grid grid-cols-[minmax(0,1fr)_minmax(0,1fr)] items-start gap-3 border-b border-slate-100 pb-2 text-sm last:border-b-0 last:pb-0"
                  >
                    <p className="font-semibold text-slate-800">{column.label[locale]}</p>
                    <p className="text-right text-slate-700 break-words">{formatValue(row[column.key], locale)}</p>
                  </div>
                ))}
              </div>
            </article>
          ))}
        </div>
      ) : null}
    </div>
  );
}

