                className="text-xs font-semibold text-emerald-700 underline-offset-4 hover:underline"
                target="_blank"
                rel="noreferrer"
                aria-label={link.label}
              >
                {copy.sourcesLabel}: {link.label}
              </Link>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
}

