import { useEffect, useMemo, useState, type ChangeEvent, type FormEvent } from "react";
import useFirebaseServices from "@/components/firebase/useFirebaseServices";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { getMessages } from "@/utils/messages";

type AttachmentPayload = {
  url: string;
  name?: string;
  size?: number;
  type?: string;
};

const MAX_ATTACHMENT_SIZE = 10 * 1024 * 1024;

export default function SupportForm() {
  const { locale } = useLocale();
  const copy = getMessages(locale).components.supportForm;
  const { services } = useFirebaseServices();
  const storage = services?.storage ?? null;
  const canUploadFile = Boolean(storage);

  const [form, setForm] = useState({ name: "", email: "", message: "" });
  const [attachment, setAttachment] = useState<File | null>(null);
  const [status, setStatus] = useState<"idle" | "uploading" | "submitting" | "success" | "error">("idle");
  const [errorMessage, setErrorMessage] = useState("");
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  const isBusy = status === "uploading" || status === "submitting";

  const submitLabel = useMemo(() => {
    if (status === "uploading") return copy.submit.uploading;
    if (status === "submitting") return copy.submit.submitting;
    return copy.submit.idle;
  }, [status, copy]);

  useEffect(() => {
    if (status !== "success") return;
    setToastMessage(copy.successToast ?? copy.success);
  }, [status, copy.successToast, copy.success]);

  useEffect(() => {
    if (!toastMessage) return;
    const timer = setTimeout(() => setToastMessage(null), 4000);
    return () => clearTimeout(timer);
  }, [toastMessage]);

  const handleChange = (field: "name" | "email" | "message") =>
    (event: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      if (status !== "idle") setStatus("idle");
      if (errorMessage) setErrorMessage("");
      setForm((prev) => ({ ...prev, [field]: event.target.value }));
    };

  const handleFileChange = (event: ChangeEvent<HTMLInputElement>) => {
    if (status !== "idle") setStatus("idle");
    const file = event.target.files?.[0] ?? null;
    if (!file) {
      setAttachment(null);
      return;
    }

    if (file.size > MAX_ATTACHMENT_SIZE) {
      setAttachment(null);
      setErrorMessage(copy.errors.fileTooLarge);
      return;
    }

    setErrorMessage("");
    setAttachment(file);
  };

  const uploadAttachment = async (file: File): Promise<AttachmentPayload> => {
    if (!storage) {
      throw new Error(copy.errors.uploadUnavailable);
    }

    const { getDownloadURL, ref, uploadBytes } = await import("firebase/storage");
    const safeName = file.name.replace(/[^a-zA-Z0-9._-]/g, "_");
    const path = `support/${Date.now()}-${safeName}`;
    const fileRef = ref(storage, path);
    await uploadBytes(fileRef, file);
    const url = await getDownloadURL(fileRef);
    return { url, name: file.name, size: file.size, type: file.type };
  };

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setErrorMessage("");

    if (!form.name.trim() || !form.email.trim() || !form.message.trim()) {
      setErrorMessage(copy.errors.required);
      setStatus("error");
      return;
    }

    let attachmentPayload: AttachmentPayload | undefined;

    try {
      if (attachment) {
        setStatus("uploading");
        attachmentPayload = await uploadAttachment(attachment);
      }

      setStatus("submitting");
      const response = await fetch("/api/support", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: form.name.trim(),
          email: form.email.trim(),
          message: form.message.trim(),
          attachment: attachmentPayload,
        }),
      });

      if (!response.ok) {
        const data = await response.json().catch(() => null);
        if (data?.error === "support_unavailable") {
          throw new Error(copy.errors.supportUnavailable);
        }
        throw new Error(data?.error ?? copy.errors.submitFailed);
      }

      setStatus("success");
      setForm({ name: "", email: "", message: "" });
      setAttachment(null);
    } catch (error) {
      console.error("[support] submit failed", error);
      setStatus("error");
      setErrorMessage(error instanceof Error ? error.message : copy.errors.submitFailed);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="mt-4 space-y-4 rounded-2xl border border-emerald-100 bg-emerald-50/60 p-4 shadow-sm"
    >
      {toastMessage ? (
        <div
          role="status"
          aria-live="polite"
          className="fixed bottom-6 right-6 z-50 rounded-2xl border border-emerald-200 bg-white px-4 py-3 text-xs font-semibold text-emerald-700 shadow-lg"
        >
          {toastMessage}
        </div>
      ) : null}
      <div className="grid gap-3 md:grid-cols-2">
        <div className="space-y-1">
          <label className="text-xs font-semibold text-slate-700" htmlFor="name">
            {copy.fields.name.label}
          </label>
          <input
            id="name"
            name="name"
            required
            value={form.name}
            onChange={handleChange("name")}
            className="w-full rounded-xl border border-emerald-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none transition focus:border-emerald-400 focus:ring-2 focus:ring-emerald-100"
            placeholder={copy.fields.name.placeholder}
            disabled={isBusy}
          / aria-label={copy.fields.name.placeholder}>
        </div>
        <div className="space-y-1">
          <label className="text-xs font-semibold text-slate-700" htmlFor="email">
            {copy.fields.email.label}
          </label>
          <input
            id="email"
            name="email"
            type="email"
            required
            value={form.email}
            onChange={handleChange("email")}
            className="w-full rounded-xl border border-emerald-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none transition focus:border-emerald-400 focus:ring-2 focus:ring-emerald-100"
            placeholder={copy.fields.email.placeholder}
            disabled={isBusy}
          / aria-label={copy.fields.email.placeholder}>
        </div>
      </div>

      <div className="space-y-1">
        <label className="text-xs font-semibold text-slate-700" htmlFor="message">
          {copy.fields.message.label}
        </label>
        <textarea
          id="message"
          name="message"
          rows={4}
          required
          value={form.message}
          onChange={handleChange("message")}
          className="w-full rounded-xl border border-emerald-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none transition focus:border-emerald-400 focus:ring-2 focus:ring-emerald-100"
          placeholder={copy.fields.message.placeholder}
          disabled={isBusy}
        / aria-label={copy.fields.message.placeholder}>
      </div>

      <div className="space-y-1">
        <label className="text-xs font-semibold text-slate-700" htmlFor="attachment">
          {copy.fields.attachment.label}
        </label>
        <input
          id="attachment"
          name="attachment"
          type="file"
          onChange={handleFileChange}
          disabled={!canUploadFile || isBusy}
          className="block w-full text-sm text-slate-700 file:mr-3 file:rounded-lg file:border-0 file:bg-emerald-600 file:px-3 file:py-1.5 file:text-xs file:font-semibold file:text-white hover:file:bg-emerald-500 disabled:opacity-60"
        / aria-label="attachment">
        <p className="text-[11px] text-slate-600">
          {canUploadFile ? copy.fields.attachment.helper : copy.fields.attachment.unavailable}
        </p>
      </div>

      {status === "success" ? (
        <p className="rounded-xl border border-emerald-200 bg-white px-3 py-2 text-xs text-emerald-700">
          {copy.success}
        </p>
      ) : null}

      {status === "error" && errorMessage ? (
        <p className="rounded-xl border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-700">
          {errorMessage}
        </p>
      ) : null}

      <button
        type="submit"
        disabled={isBusy}
        className="tap-target w-full rounded-full bg-emerald-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-emerald-500 disabled:cursor-not-allowed disabled:opacity-60"
      >
        {submitLabel}
      </button>
    </form>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState, type ComponentProps } from "react";
import { usePathname, useSearchParams } from "next/navigation";
import PageShell from "@/components/layout/PageShell";
import ToolDocTabs from "@/components/tools/ToolDocTabs";
import ToolActions from "@/components/tools/ToolActions";
import ToolDataActions from "@/components/tools/ToolDataActions";
import ToolTrustPanel from "@/components/tools/ToolTrustPanel";
import ToolMethodNotes from "@/components/tools/ToolMethodNotes";
import AccessBadge from "@/components/tools/AccessBadge";
import ToolBadge from "@/components/tools/ToolBadge";
import InfoTooltip from "@/components/ui/InfoTooltip";
import AISummaryPanel from "@/src/components/ai/AISummaryPanel";
import { useLocale } from "@/components/i18n/LocaleProvider";
import AdvisorPanel from "@/src/components/tools/AdvisorPanel";
import { getAdvisorInsights } from "@/src/lib/advisor/engine";
import { formatMessage, getMessages } from "@/utils/messages";
import { resolveLocalizedValue } from "@/utils/locale-values";
import { withLocalePrefix } from "@/utils/locale-path";
import { buildShareUrl, decodeToolState, encodeToolState } from "@/utils/tool-share";
import { warnIfEnglishLabelsInTurkish } from "@/utils/ui-labels";
import { getToolById, type ToolDefinition, type ToolInputDefinition, type ToolInputOption } from "@/tools/registry";
import { getToolMethodNotes } from "@/lib/tool-method-notes";
import { toolCatalog } from "@/tools/_shared/catalog";
import { categoryLabels } from "@/src/lib/i18n/categoryLabels";

type GenericToolPageProps = {
  toolId: string;
  initialDocs?: ComponentProps<typeof ToolDocTabs>["initialDocs"];
};

type ChartModule = typeof import("chart.js");
type ChartInstance = import("chart.js").Chart;

let chartModulePromise: Promise<ChartModule> | null = null;
let chartRegistered = false;

const loadChartModule = async () => {
  chartModulePromise ??= import("chart.js");
  const chartModule = await chartModulePromise;

  if (!chartRegistered) {
    chartModule.Chart.register(
      chartModule.LineController,
      chartModule.LineElement,
      chartModule.PointElement,
      chartModule.LinearScale,
      chartModule.CategoryScale,
      chartModule.Tooltip,
      chartModule.Legend,
      chartModule.BarController,
      chartModule.BarElement,
    );
    chartRegistered = true;
  }

  return chartModule;
};

const getDefaultValues = (inputs: ToolInputDefinition[]) =>
  inputs.reduce<Record<string, string>>((acc, input) => {
    acc[input.key] = String(input.default ?? "");
    return acc;
  }, {});

type GenericToolInputs = Record<string, unknown>;

const formatKey = (value: string) =>
  value
    .replace(/[_-]+/g, " ")
    .replace(/([a-z])([A-Z])/g, "$1 $2")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/^./, (char) => char.toUpperCase());

const isPrimitive = (value: unknown) =>
  value === null ||
  value === undefined ||
  typeof value === "string" ||
  typeof value === "number" ||
  typeof value === "boolean";

export default function GenericToolPage({ toolId, initialDocs }: GenericToolPageProps) {
  const { locale } = useLocale();
  const messages = getMessages(locale);
  const copy = messages.components.genericToolPage;
  const toolPageCopy = messages.components.toolPage;
  const validationCopy = messages.components.toolValidation;
  const calcFailedCopy = copy.calcFailed;
  const common = messages.common;
  const tool = getToolById(toolId) as ToolDefinition<GenericToolInputs, Record<string, unknown>> | null;
  const catalogEntry = tool ? toolCatalog.find((item) => item.id === tool.id) ?? null : null;
  const access = catalogEntry?.access ?? "free";
  const status = catalogEntry?.status ?? "verified";
  const validationStandard = catalogEntry?.validationStandard;
  const accessLabel = messages.common.access?.[access] ?? messages.common.access?.free ?? "";
  const [values, setValues] = useState<Record<string, string>>(() => getDefaultValues(tool?.inputs ?? []));
  const chartRef = useRef<ChartInstance | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const searchParams = useSearchParams();
  const pathname = usePathname();
  const hasHydrated = useRef(false);

  useEffect(() => {
    if (!tool) return;
    Promise.resolve().then(() => setValues(getDefaultValues(tool.inputs)));
  }, [tool]);

  useEffect(() => {
    if (!tool) return;
    if (hasHydrated.current) return;
    const shared = decodeToolState<Record<string, string | number>>(searchParams?.get("input") ?? null);
    if (shared) {
      const defaults = getDefaultValues(tool.inputs);
      const normalized: Record<string, string> = { ...defaults };
      Object.entries(shared).forEach(([key, value]) => {
        normalized[key] = String(value);
      });
      Promise.resolve().then(() => setValues(normalized));
    }
    hasHydrated.current = true;
  }, [searchParams, tool]);

  const { errors, normalizedInputs } = validateInputs(tool?.inputs ?? [], values, validationCopy);

  let results: Record<string, unknown> | null = null;
  let calcError = "";
  if (normalizedInputs && tool) {
    try {
      results = tool.calculate(normalizedInputs);
    } catch {
      results = null;
      calcError = calcFailedCopy;
    }
  }

  const resultEntries =
    results && typeof results === "object"
      ? Object.entries(results).filter(([, value]) => isPrimitive(value))
      : [];

  const chartConfig = (() => {
    if (!results || !normalizedInputs || !tool?.chartConfig) return null;
    try {
      return tool.chartConfig(results, normalizedInputs);
    } catch {
      return null;
    }
  })();

  const formula = tool ? resolveLocalizedValue(tool.formula, locale) ?? tool.formulaDisplay : "";
  const assumptions = tool ? resolveLocalizedValue(tool.assumptions, locale) : undefined;
  const references = tool ? resolveLocalizedValue(tool.references, locale) : undefined;
  const methodNotes = tool ? getToolMethodNotes(tool.id, locale) : null;
  const categoryLabelMap = categoryLabels(locale);
  const localizedCategories = useMemo(
    () => (tool ? tool.categories.map((category) => categoryLabelMap[category] ?? category) : []),
    [categoryLabelMap, tool],
  );

  const encodedState = useMemo(() => encodeToolState(values), [values]);
  const shareUrl = useMemo(() => {
    if (!pathname) return "";
    return buildShareUrl(pathname, values);
  }, [pathname, values]);
  const reportBase = tool ? withLocalePrefix(`/tools/${tool.id}/report`, locale) : "";
  const reportUrl = encodedState ? `${reportBase}?input=${encodedState}` : reportBase;

  const showAdvisor = tool?.id === "torque-power";
  const advisorInsights =
    showAdvisor && tool
      ? getAdvisorInsights(tool.id, normalizedInputs, {
          locale,
          reportUrl: results ? reportUrl : undefined,
        })
      : [];

  useEffect(() => {
    if (!chartConfig || !canvasRef.current) {
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
      return;
    }

    const ctx = canvasRef.current.getContext("2d");
    if (!ctx) return;

    let cancelled = false;

    void (async () => {
      const { Chart } = await loadChartModule();
      if (cancelled) return;

      if (chartRef.current) {
        chartRef.current.destroy();
      }

      chartRef.current = new Chart(ctx, {
        type: chartConfig.type ?? "line",
        data: {
          labels: chartConfig.labels,
          datasets: chartConfig.datasets.map((dataset) => ({
            ...dataset,
            data: dataset.data.map((value) => (value === null ? NaN : value)),
          })),
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { display: true, labels: { boxWidth: 10, boxHeight: 10 } },
          },
          scales: {
            x: {
              title: chartConfig.xLabel ? { display: true, text: chartConfig.xLabel } : undefined,
              ticks: { color: "#64748b", font: { size: 10 } },
              grid: { color: "rgba(148, 163, 184, 0.2)" },
            },
            y: {
              title: chartConfig.yLabel ? { display: true, text: chartConfig.yLabel } : undefined,
              ticks: { color: "#64748b", font: { size: 10 } },
              grid: { color: "rgba(148, 163, 184, 0.2)" },
            },
          },
        },
      });
    })();

    return () => {
      cancelled = true;
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
    };
  }, [chartConfig]);

  useEffect(() => {
    if (!tool) return;
    warnIfEnglishLabelsInTurkish("GenericToolPage", locale, {
      title: tool.title,
      categories: localizedCategories,
    });
  }, [localizedCategories, locale, tool]);

  if (!tool) {
    const notFoundCopy = messages.pages.notFound;
    return (
      <PageShell>
        <section className="min-w-0 rounded-3xl border border-slate-200 bg-white p-6 shadow-sm">
          <div className="space-y-4">
            <div className="inline-flex items-center gap-2 rounded-full border border-rose-100 bg-rose-50 px-3 py-1 text-[11px] text-rose-700 md:text-xs">
              <span className="font-semibold">404</span>
            </div>
            <h1 className="text-balance text-2xl font-semibold leading-snug text-slate-900 md:text-4xl">
              {notFoundCopy.title}
            </h1>
            <p className="text-[15px] leading-relaxed text-slate-700 md:text-base">
              {notFoundCopy.description}
            </p>
            <div className="flex flex-wrap items-center gap-3">
              <a
                href={withLocalePrefix("/tools", locale)}
                className="rounded-full bg-emerald-600 px-5 py-2 text-xs font-semibold text-white shadow-sm transition hover:bg-emerald-700"
              >
                {notFoundCopy.primaryCta}
              </a>
              <a href={withLocalePrefix("/", locale)} className="text-xs font-semibold text-slate-500 hover:text-slate-700">
                {notFoundCopy.secondaryCta}
              </a>
            </div>
          </div>
        </section>
      </PageShell>
    );
  }

  return (
    <PageShell>
      <ToolDocTabs slug={tool.id} initialDocs={initialDocs}>
        <section className="min-w-0 rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
          <div className="mb-3 flex flex-wrap items-center gap-2">
            {accessLabel ? <AccessBadge access={access} label={accessLabel} /> : null}
            <ToolBadge status={status} standard={validationStandard} locale={locale} />
            {localizedCategories.map((category) => (
              <span
                key={category}
                className="rounded-full bg-slate-900 px-3 py-1 text-[10px] font-semibold uppercase tracking-wide text-white"
              >
                {category}
              </span>
            ))}
            {tool.tags.map((tag) => (
              <span
                key={tag}
                className="rounded-full bg-emerald-50 px-3 py-1 text-[10px] font-semibold text-emerald-700"
              >
                #{tag}
              </span>
            ))}
          </div>
          <div className="flex flex-wrap items-center gap-2">
            <h1 className="text-lg font-semibold text-slate-900">{tool.title}</h1>
            <InfoTooltip
              label={toolPageCopy.howItWorksLabel}
              content={toolPageCopy.howItWorksDescription}
            />
          </div>
          <p className="mt-2 text-xs text-slate-600">{tool.description}</p>
        </section>

        <section className="grid min-w-0 gap-4 lg:grid-cols-[minmax(0,1.1fr)_minmax(0,0.9fr)]">
          <div className="min-w-0 rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
            <h2 className="mb-3 text-sm font-semibold text-slate-900">{copy.inputs}</h2>
            <div className="grid gap-3 sm:grid-cols-2">
              {tool.inputs.map((input) => (
                <InputField
                  key={input.key}
                  input={input}
                  value={values[input.key] ?? ""}
                  error={errors[input.key]}
                  onChange={(next) => setValues((prev) => ({ ...prev, [input.key]: next }))}
                  locale={locale}
                />
              ))}
            </div>
          </div>

          <div className="min-w-0 rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
            <h2 className="mb-3 text-sm font-semibold text-slate-900">{copy.results}</h2>
            {normalizedInputs && results ? (
              <div className="space-y-2">
                {resultEntries.map(([key, value]) => (
                  <ResultRow key={key} label={formatKey(key)} value={formatValue(value, locale, common)} />
                ))}
              </div>
            ) : (
              <p className="text-[11px] text-red-600">{calcError || copy.resultEmpty}</p>
            )}
          </div>
        </section>

        {normalizedInputs && results ? (
          <ToolDataActions
            toolSlug={tool.id}
            toolTitle={tool.title}
            inputs={values}
            outputs={results}
            reportUrl={reportUrl}
          />
        ) : null}

        {normalizedInputs && results && tool.id === "torque-power" ? (
          <AISummaryPanel
            locale={locale}
            toolId={tool.id}
            toolName={tool.title}
            inputs={normalizedInputs as Record<string, unknown>}
            outputs={results}
          />
        ) : null}

        {showAdvisor ? <AdvisorPanel insights={advisorInsights} /> : null}

        <section className="min-w-0 rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
          <div className="space-y-2">
            <h2 className="text-sm font-semibold text-slate-900">{copy.actionsTitle}</h2>
            <p className="text-[11px] text-slate-500">{copy.actionsDescription}</p>
          </div>
          <div className="mt-3">
            <ToolActions shareUrl={shareUrl} reportUrl={reportUrl} />
          </div>
        </section>

        <ToolTrustPanel formula={formula} assumptions={assumptions} references={references} />
        {methodNotes ? <ToolMethodNotes notes={methodNotes} /> : null}

        {chartConfig ? (
          <section className="min-w-0 overflow-hidden rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
            <h2 className="mb-2 text-sm font-semibold text-slate-900">{copy.chart}</h2>
            <div className="h-64 w-full">
              <canvas ref={canvasRef} className="h-full w-full" />
            </div>
          </section>
        ) : (
          tool.chartConfig && (
            <section className="min-w-0 rounded-2xl border border-dashed border-slate-200 bg-white p-5 text-xs text-slate-500">
              {copy.chartEmpty}
            </section>
          )
        )}
      </ToolDocTabs>
    </PageShell>
  );
}

function validateInputs(
  inputs: ToolInputDefinition[],
  values: Record<string, string>,
  copy: Record<string, string>,
) {
  const errors: Record<string, string> = {};
  const normalized: Record<string, unknown> = {};

  for (const input of inputs) {
    const label = input.unit ? `${input.label} (${input.unit})` : input.label;
    const rawValue = values[input.key] ?? "";

    if (input.type === "select") {
      if (!String(rawValue).trim()) {
        errors[input.key] = formatMessage(copy.required, { field: label });
        continue;
      }

      const option = findOption(input.options, rawValue);
      if (option === null) {
        errors[input.key] = formatMessage(copy.invalidOption, { field: label });
        continue;
      }

      normalized[input.key] = option;
      continue;
    }

    const parsed = Number(rawValue);
    if (String(rawValue).trim().length === 0) {
      errors[input.key] = formatMessage(copy.required, { field: label });
      continue;
    }

    if (!Number.isFinite(parsed)) {
      errors[input.key] = formatMessage(copy.invalidNumber, { field: label });
      continue;
    }

    if (typeof input.min === "number" && parsed < input.min) {
      errors[input.key] = formatMessage(copy.min, {
        field: label,
        min: input.unit ? `${input.min} ${input.unit}` : input.min,
      });
      continue;
    }

    if (typeof input.max === "number" && parsed > input.max) {
      errors[input.key] = formatMessage(copy.max, {
        field: label,
        max: input.unit ? `${input.max} ${input.unit}` : input.max,
      });
      continue;
    }

    normalized[input.key] = parsed;
  }

  return {
    errors,
    normalizedInputs: Object.keys(errors).length > 0 ? null : (normalized as GenericToolInputs),
  };
}

function findOption(options: ToolInputOption[] | undefined, value: unknown) {
  if (!options || options.length === 0) return null;
  const match = options.find((option) => String(option.value) === String(value));
  return match ? match.value : null;
}

function InputField({
  input,
  value,
  error,
  onChange,
  locale,
}: {
  input: ToolInputDefinition;
  value: string;
  error?: string;
  onChange: (next: string) => void;
  locale: "tr" | "en";
}) {
  const label = input.unit ? `${input.label} (${input.unit})` : input.label;
  const ariaLabel = input.unit ? `${input.label} ${input.unit}` : input.label;

  if (input.type === "select") {
    return (
      <label className="min-w-0 space-y-1">
        <span className="block text-[11px] font-medium text-slate-700">{label}</span>
        <select
          value={value}
          onChange={(event) = aria-label="Select field"> onChange(event.target.value)}
          className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
          aria-label={ariaLabel}
        >
          {(input.options ?? []).map((option) => (
            <option key={`${input.key}-${option.value}`} value={String(option.value)}>
              {option.label}
            </option>
          ))}
        </select>
        {input.help ? <span className="text-[10px] text-slate-500">{input.help}</span> : null}
        {error ? <span className="text-[10px] text-red-600">{error}</span> : null}
      </label>
    );
  }

  if (input.type === "slider") {
    const displayValue = value || String(input.min ?? 0);
    return (
      <label className="min-w-0 space-y-1">
        <span className="block text-[11px] font-medium text-slate-700">{label}</span>
        <div className="flex items-center gap-3">
          <input
            type="range"
            min={input.min}
            max={input.max}
            step={input.step ?? 1}
            value={displayValue}
            onChange={(event) = aria-label="Input field"> onChange(event.target.value)}
            className="w-full accent-emerald-500"
            aria-label={ariaLabel}
          />
          <span className="min-w-[48px] text-[11px] font-semibold text-slate-700">
            {displayValue}
            {input.unit ? ` ${input.unit}` : ""}
          </span>
        </div>
        {input.help ? <span className="text-[10px] text-slate-500">{input.help}</span> : null}
        {error ? <span className="text-[10px] text-red-600">{error}</span> : null}
      </label>
    );
  }

  return (
    <label className="min-w-0 space-y-1">
      <span className="block text-[11px] font-medium text-slate-700">{label}</span>
      <input
        type="number"
        value={value}
        onChange={(event) = aria-label="Number input"> onChange(event.target.value)}
        min={input.min}
        max={input.max}
        step={input.step ?? "any"}
        className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
        aria-label={ariaLabel}
        inputMode={locale === "en" ? "decimal" : "numeric"}
      />
      {input.help ? <span className="text-[10px] text-slate-500">{input.help}</span> : null}
      {error ? <span className="text-[10px] text-red-600">{error}</span> : null}
    </label>
  );
}

function ResultRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex min-w-0 items-center justify-between gap-3 rounded-lg bg-slate-50 px-3 py-1.5">
      <span className="min-w-0 text-[11px] text-slate-600">{label}</span>
      <span className="min-w-0 break-all text-right font-mono text-[11px] font-semibold text-slate-900">{value}</span>
    </div>
  );
}

function formatValue(value: unknown, locale: "tr" | "en", common: { yes: string; no: string }) {
  if (value === null || value === undefined || value === "") return "-";
  if (typeof value === "boolean") {
    return value ? common.yes : common.no;
  }
  if (typeof value === "number") {
    if (!Number.isFinite(value)) return "-";
    return value.toLocaleString(locale === "en" ? "en-US" : "tr-TR", { maximumFractionDigits: 4 });
  }
  return String(value);
}

"use client";

import { useMemo, useState } from "react";
import Link from "next/link";
import { useLocale } from "@/components/i18n/LocaleProvider";
import { formatMessage, getMessages } from "@/utils/messages";
import { withLocalePrefix } from "@/utils/locale-path";
import { buildProjectItem, readProjects, saveProjectItem, type Project } from "@/lib/projects/storage";

type ToolDataActionsProps = {
  toolSlug: string;
  toolTitle: string;
  inputs: Record<string, unknown>;
  outputs: Record<string, unknown> | null;
  reportUrl?: string;
};

type ExportRow = { section: string; key: string; value: string };

const isPrimitive = (value: unknown) =>
  value === null ||
  value === undefined ||
  typeof value === "string" ||
  typeof value === "number" ||
  typeof value === "boolean";

const sanitizeRecord = (input: Record<string, unknown>) =>
  Object.entries(input).reduce<Record<string, unknown>>((acc, [key, value]) => {
    if (isPrimitive(value)) {
      acc[key] = value;
    }
    return acc;
  }, {});

const formatValue = (value: unknown) => {
  if (value === null || value === undefined) return "";
  if (typeof value === "boolean") return value ? "true" : "false";
  return String(value);
};

const downloadBlob = (filename: string, content: string, type: string) => {
  const blob = new Blob([content], { type });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
};

const escapeCsv = (value: string) => {
  if (value.includes("\"") || value.includes(",") || value.includes("\n")) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

const getDefaultProjectTitle = (value?: string) => value?.trim() || "My Project";

export default function ToolDataActions({ toolSlug, toolTitle, inputs, outputs, reportUrl }: ToolDataActionsProps) {
  const { locale } = useLocale();
  const messages = getMessages(locale);
  const copy = messages.components.toolDataActions;

  const [projects, setProjects] = useState<Project[]>(() => readProjects());
  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
    const stored = readProjects();
    return stored.length > 0 ? stored[0].id : "new";
  });
  const [newProjectTitle, setNewProjectTitle] = useState<string>(() => getDefaultProjectTitle(copy.defaultProject));
  const [status, setStatus] = useState<string>("");

  const safeInputs = useMemo(() => sanitizeRecord(inputs), [inputs]);
  const safeOutputs = useMemo(() => (outputs ? sanitizeRecord(outputs) : null), [outputs]);

  const handleSave = () => {
    if (!safeOutputs) return;
    const isNew = selectedProjectId === "new" || !projects.find((project) => project.id === selectedProjectId);
    const title = (isNew ? newProjectTitle.trim() : "") || getDefaultProjectTitle(copy.defaultProject);

    const item = buildProjectItem({
      toolSlug,
      inputs: safeInputs,
      outputs: safeOutputs,
      reportMeta: {
        title: toolTitle,
        reportUrl,
      },
    });

    const { projects: nextProjects, project } = saveProjectItem({
      projectId: isNew ? undefined : selectedProjectId,
      projectTitle: title,
      item,
    });

    setProjects(nextProjects);
    setSelectedProjectId(project.id);
    setStatus(formatMessage(copy.savedMessage, { project: project.title }));
    window.setTimeout(() => setStatus(""), 2500);
  };

  const handleExportJson = () => {
    if (!safeOutputs) return;
    const payload = {
      inputs: safeInputs,
      outputs: safeOutputs,
    };
    const json = JSON.stringify(payload, null, 2);
    const filename = `${toolSlug.replace(/\//g, "-")}-export.json`;
    downloadBlob(filename, json, "application/json;charset=utf-8");
  };

  const handleExportCsv = () => {
    if (!safeOutputs) return;
    const rows: ExportRow[] = [];
    Object.entries(safeInputs).forEach(([key, value]) => {
      rows.push({ section: copy.sections.inputs, key, value: formatValue(value) });
    });
    Object.entries(safeOutputs).forEach(([key, value]) => {
      rows.push({ section: copy.sections.outputs, key, value: formatValue(value) });
    });
    const header = [copy.csvHeaders.section, copy.csvHeaders.key, copy.csvHeaders.value].map(escapeCsv).join(",");
    const lines = rows.map((row) =>
      [row.section, row.key, row.value].map((value) => escapeCsv(value)).join(","),
    );
    const csv = [header, ...lines].join("\n");
    const filename = `${toolSlug.replace(/\//g, "-")}-export.csv`;
    downloadBlob(filename, csv, "text/csv;charset=utf-8");
  };

  const projectsHref = withLocalePrefix("/projects", locale);
  const hasResults = Boolean(safeOutputs);

  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-4 text-xs shadow-sm">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="space-y-1">
          <h2 className="text-sm font-semibold text-slate-900">{copy.title}</h2>
          <p className="text-[11px] text-slate-500">{copy.description}</p>
        </div>
        <Link
          href={projectsHref}
          className="rounded-full border border-slate-200 px-3 py-1 text-[11px] font-semibold text-slate-600 transition hover:border-slate-300 hover:text-slate-900"
        >
          {copy.openProjects}
        </Link>
      </div>

      <div className="mt-4 grid gap-3 lg:grid-cols-[minmax(0,1.2fr)_minmax(0,0.8fr)]">
        <div className="space-y-2">
          <label className="text-[11px] font-medium text-slate-700">{copy.projectLabel}</label>
          <div className="flex flex-wrap gap-2">
            <select
              value={selectedProjectId}
              onChange={(event) = aria-label="Select field"> setSelectedProjectId(event.target.value)}
              className="min-w-[180px] rounded-lg border border-slate-300 px-2 py-1.5 text-[11px] text-slate-700"
            >
              {projects.map((project) => (
                <option key={project.id} value={project.id}>
                  {project.title}
                </option>
              ))}
              <option value="new">{copy.newProject}</option>
            </select>
            {selectedProjectId === "new" ? (
              <input
                type="text"
                value={newProjectTitle}
                onChange={(event) = aria-label="Input field"> setNewProjectTitle(event.target.value)}
                placeholder={copy.newProjectPlaceholder}
                className="min-w-[180px] rounded-lg border border-slate-300 px-2 py-1.5 text-[11px] text-slate-700"
              />
            ) : null}
            <button
              type="button"
              onClick={handleSave}
              disabled={!hasResults}
              className={`rounded-full px-3 py-1.5 text-[11px] font-semibold transition ${
                hasResults
                  ? "bg-slate-900 text-white hover:bg-slate-800"
                  : "cursor-not-allowed bg-slate-200 text-slate-500"
              }`}
            >
              {copy.save}
            </button>
            {status ? <span className="text-[11px] text-emerald-600">{status}</span> : null}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[11px] font-medium text-slate-700">{copy.exportLabel}</label>
          <div className="flex flex-wrap gap-2">
            <button
              type="button"
              onClick={handleExportJson}
              disabled={!hasResults}
              className={`rounded-full border px-3 py-1.5 text-[11px] font-semibold transition ${
                hasResults
                  ? "border-slate-300 text-slate-700 hover:border-slate-400"
                  : "cursor-not-allowed border-slate-200 text-slate-400"
              }`}
            >
              {copy.exportJson}
            </button>
            <button
              type="button"
              onClick={handleExportCsv}
              disabled={!hasResults}
              className={`rounded-full border px-3 py-1.5 text-[11px] font-semibold transition ${
                hasResults
                  ? "border-slate-300 text-slate-700 hover:border-slate-400"
                  : "cursor-not-allowed border-slate-200 text-slate-400"
              }`}
            >
              {copy.exportCsv}
            </button>
          </div>
          <p className="text-[10px] text-slate-500">{copy.exportHint}</p>
        </div>
      </div>
    </section>
  );
}

"use client";

import { useEffect, useRef } from "react";
import type { ToolChartConfig } from "@/tools/registry";

type ChartModule = typeof import("chart.js");
type ChartInstance = import("chart.js").Chart;

let chartModulePromise: Promise<ChartModule> | null = null;
let chartRegistered = false;

const loadChartModule = async () => {
  chartModulePromise ??= import("chart.js");
  const chartModule = await chartModulePromise;

  if (!chartRegistered) {
    chartModule.Chart.register(
      chartModule.LineController,
      chartModule.LineElement,
      chartModule.PointElement,
      chartModule.LinearScale,
      chartModule.CategoryScale,
      chartModule.Tooltip,
      chartModule.Legend,
      chartModule.BarController,
      chartModule.BarElement,
    );
    chartRegistered = true;
  }

  return chartModule;
};

export default function ReportChart({ config }: { config: ToolChartConfig }) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const chartRef = useRef<ChartInstance | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const ctx = canvasRef.current.getContext("2d");
    if (!ctx) return;

    let cancelled = false;

    void (async () => {
      const { Chart } = await loadChartModule();
      if (cancelled) return;

      if (chartRef.current) {
        chartRef.current.destroy();
      }

      chartRef.current = new Chart(ctx, {
        type: config.type ?? "line",
        data: {
          labels: config.labels,
          datasets: config.datasets.map((dataset) => ({
            ...dataset,
            data: dataset.data.map((value) => (value === null ? NaN : value)),
          })),
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { display: true, labels: { boxWidth: 10, boxHeight: 10 } },
          },
          scales: {
            x: {
              title: config.xLabel ? { display: true, text: config.xLabel } : undefined,
              ticks: { color: "#64748b", font: { size: 10 } },
              grid: { color: "rgba(148, 163, 184, 0.2)" },
            },
            y: {
              title: config.yLabel ? { display: true, text: config.yLabel } : undefined,
              ticks: { color: "#64748b", font: { size: 10 } },
              grid: { color: "rgba(148, 163, 184, 0.2)" },
            },
          },
        },
      });
    })();

    return () => {
      cancelled = true;
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
    };
  }, [config]);

  return (
    <div className="h-64 w-full">
      <canvas ref={canvasRef} className="h-full w-full" />
    </div>
  );
}

"use client";

import { useDeferredValue, useEffect, useMemo, useRef } from "react";
import { useDebouncedValue } from "@/components/search/useDebouncedValue";
import type { BoltInput, BoltResult } from "@/tools/bolt-calculator/types";
import type { BoltVisualizationCopy } from "@/tools/bolt-calculator/copy";
import { getYieldStrength } from "@/tools/bolt-calculator/logic";
import { formatNumberFixed } from "@/utils/number-format";

type ChartModule = typeof import("chart.js");
type ChartInstance = import("chart.js").Chart;

type BoltVisualizationProps = {
  input: BoltInput;
  result: BoltResult;
  locale: "tr" | "en";
  copy: BoltVisualizationCopy;
};

let chartModulePromise: Promise<ChartModule> | null = null;
let chartRegistered = false;

const loadChartModule = async () => {
  chartModulePromise ??= import("chart.js");
  const chartModule = await chartModulePromise;

  if (!chartRegistered) {
    chartModule.Chart.register(
      chartModule.BarController,
      chartModule.BarElement,
      chartModule.LinearScale,
      chartModule.CategoryScale,
      chartModule.Tooltip,
      chartModule.Legend,
    );
    chartRegistered = true;
  }

  return chartModule;
};

const clamp = (value: number, min: number, max: number) => Math.min(Math.max(value, min), max);

function buildThreadPath(startX: number, endX: number, topY: number, bottomY: number, count: number) {
  const safeCount = Math.max(4, count);
  const step = (endX - startX) / safeCount;
  const midY = (topY + bottomY) / 2;

  let path = `M ${startX} ${midY}`;
  for (let i = 0; i <= safeCount; i += 1) {
    const x = startX + i * step;
    const y = i % 2 === 0 ? topY : bottomY;
    path += ` L ${x} ${y}`;
  }

  return path;
}

export default function BoltVisualization({ input, result, locale, copy }: BoltVisualizationProps) {
  const deferredInput = useDeferredValue(input);
  const deferredResult = useDeferredValue(result);
  const debouncedInput = useDebouncedValue(deferredInput, 150);
  const debouncedResult = useDebouncedValue(deferredResult, 150);
  const chartRef = useRef<ChartInstance | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  const parsed = useMemo(() => {
    const d = Number(debouncedInput.d);
    const P = Number(debouncedInput.P);
    const preload = Number(debouncedInput.preloadPercent);
    const sigma = debouncedResult.sigma ?? null;
    const re = getYieldStrength(debouncedInput.grade);

    return {
      d: Number.isFinite(d) ? d : 0,
      P: Number.isFinite(P) ? P : 0,
      preloadPercent: Number.isFinite(preload) ? clamp(preload, 0, 100) : 0,
      sigma: sigma !== null && Number.isFinite(sigma) ? sigma : 0,
      re,
    };
  }, [debouncedInput, debouncedResult]);

  const chartData = useMemo(
    () => ({
      labels: [copy.chartSigmaLabel, copy.chartYieldLabel],
      values: [parsed.sigma, parsed.re],
    }),
    [copy.chartSigmaLabel, copy.chartYieldLabel, parsed.re, parsed.sigma],
  );

  const schematic = useMemo(() => {
    const dNorm = clamp((parsed.d - 3) / 17, 0, 1);
    const pNorm = clamp((parsed.P - 0.5) / 2, 0, 1);

    const shankHeight = 24 + dNorm * 28;
    const bodyTop = 70 - shankHeight / 2;
    const bodyBottom = bodyTop + shankHeight;
    const bodyStart = 88;
    const bodyEnd = 300;
    const threadStart = 196;
    const threadCount = Math.round(16 - pNorm * 8);
    const headWidth = 56;
    const headHeight = shankHeight + 16;
    const headTop = 70 - headHeight / 2;

    return {
      bodyTop,
      bodyBottom,
      bodyStart,
      bodyEnd,
      headTop,
      headWidth,
      headHeight,
      threadPathTop: buildThreadPath(threadStart, bodyEnd, bodyTop, bodyTop + 8, threadCount),
      threadPathBottom: buildThreadPath(threadStart, bodyEnd, bodyBottom, bodyBottom - 8, threadCount),
    };
  }, [parsed.P, parsed.d]);

  const gaugeStyle = useMemo(
    () => ({
      background: `conic-gradient(#10b981 ${parsed.preloadPercent * 3.6}deg, #e2e8f0 0deg)`,
    }),
    [parsed.preloadPercent],
  );

  useEffect(() => {
    if (!canvasRef.current) return;
    const ctx = canvasRef.current.getContext("2d");
    if (!ctx) return;

    let cancelled = false;

    void (async () => {
      const { Chart } = await loadChartModule();
      if (cancelled) return;

      if (chartRef.current) {
        chartRef.current.destroy();
      }

      chartRef.current = new Chart(ctx, {
        type: "bar",
        data: {
          labels: chartData.labels,
          datasets: [
            {
              label: copy.chartSeriesLabel,
              data: chartData.values,
              borderRadius: 8,
              borderSkipped: false,
              backgroundColor: ["rgba(14,165,233,0.8)", "rgba(16,185,129,0.8)"],
            },
          ],
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          animation: false,
          plugins: {
            legend: { display: false },
            tooltip: {
              callbacks: {
                label: (context) => {
                  const value = Number(context.raw ?? 0);
                  const formatted = formatNumberFixed(value, locale, 1);
                  return `${formatted} MPa`;
                },
              },
            },
          },
          scales: {
            x: {
              ticks: { color: "#64748b", font: { size: 11 } },
              grid: { display: false },
            },
            y: {
              beginAtZero: true,
              ticks: { color: "#64748b", font: { size: 11 } },
              grid: { color: "rgba(148,163,184,0.2)" },
            },
          },
        },
      });
    })();

    return () => {
      cancelled = true;
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
    };
  }, [chartData, copy.chartSeriesLabel, locale]);

  return (
    <div className="min-w-0 space-y-4">
      <div className="grid min-w-0 gap-4 lg:grid-cols-[minmax(0,1.2fr)_minmax(0,0.8fr)]">
        <article className="min-w-0 rounded-xl border border-slate-200 bg-white p-4">
          <h3 className="mb-2 text-xs font-semibold text-slate-700">
            {copy.chartTitle}
          </h3>
          <div className="h-52 w-full">
            <canvas ref={canvasRef} className="h-full w-full" />
          </div>
        </article>

        <article className="min-w-0 rounded-xl border border-slate-200 bg-white p-4">
          <h3 className="text-xs font-semibold text-slate-700">{copy.preloadTitle}</h3>
          <div className="mt-4 flex items-center gap-4">
            <div className="grid h-20 w-20 place-items-center rounded-full p-1" style={gaugeStyle}>
              <div className="grid h-full w-full place-items-center rounded-full bg-white text-[11px] font-semibold text-slate-700">
                {formatNumberFixed(parsed.preloadPercent, locale, 0)}
                {copy.preloadGaugeUnit}
              </div>
            </div>
            <div className="space-y-1 text-[11px] text-slate-600">
              <p>
                {copy.sigmaLabel}:{" "}
                <span className="font-semibold text-slate-900">{formatNumberFixed(parsed.sigma, locale, 1)} MPa</span>
              </p>
              <p>
                {copy.yieldLabel}:{" "}
                <span className="font-semibold text-slate-900">{formatNumberFixed(parsed.re, locale, 0)} MPa</span>
              </p>
            </div>
          </div>
          <div className="mt-3 h-2 w-full rounded-full bg-slate-200">
            <div className="h-2 rounded-full bg-emerald-500 transition-[width] duration-150" style={{ width: `${parsed.preloadPercent}%` }} />
          </div>
        </article>
      </div>

      <article className="min-w-0 rounded-xl border border-slate-200 bg-white p-4">
        <h3 className="mb-2 text-xs font-semibold text-slate-700">{copy.schematicTitle}</h3>
        <div className="overflow-x-auto">
          <svg viewBox="0 0 320 140" className="h-auto min-w-[280px] w-full" role="img" aria-label={copy.schematicAria}>
            <rect x="20" y={schematic.headTop} width={schematic.headWidth} height={schematic.headHeight} rx="8" fill="#0f172a" />
            <rect
              x={schematic.bodyStart}
              y={schematic.bodyTop}
              width={schematic.bodyEnd - schematic.bodyStart}
              height={schematic.bodyBottom - schematic.bodyTop}
              rx="8"
              fill="#1e293b"
            />
            <path d={schematic.threadPathTop} stroke="#38bdf8" strokeWidth="2" fill="none" />
            <path d={schematic.threadPathBottom} stroke="#38bdf8" strokeWidth="2" fill="none" />
          </svg>
        </div>
      </article>
    </div>
  );
}
